export const tutorialsLongformI18n: TutorialLongformI18n = {
  "open-design-in-20-minutes-coding-menace": {
    "ja": {
      title: "20分でわかるOpen Design — セットアップからデモまで完全ガイド",
      summary: "Open Designのインストールからコーディングエージェントの接続、ワークスペースの概要、そして最初の高精細プロトタイプ作成までを一気通貫で解説する入門ガイド。CodingMenaceによる実機ファーストインプレッション動画をベースにしています。",
      bodyHtml: "<p>このガイドでは、Open Designに触れる最初の20分間を、クリーンインストールから最初のプロトタイプ生成までたどっていきます。CodingMenace（Dennis）が<a href=\"https://www.youtube.com/watch?v=QOqWZzecjuY\">実機ファーストインプレッション動画</a>でたどった流れを下敷きに、現行リリースに合わせて書き直し・更新しているので、ステップごとに沿って進められます。実際の操作は上の動画をご覧いただくか、テキスト版で読み進めてください。</p>\n\n<p><img src=\"/tutorials/open-design-in-20-minutes/01-open-design-home.webp\" alt=\"Open Designのホームページ — オープンソースかつローカル、エージェントネイティブなClaude Designの代替。\"></p>\n<p><em>Open Designは、オープンソースのClaude Design代替として位置づけられています — デスクトップファースト、エージェントネイティブ、Apache-2.0。</em></p>\n\n<h2>Open Designとは？</h2>\n<p>Open Designは、オープンソースでローカルファーストなデザインプラットフォームであり、Claude DesignやFigmaに代わるエージェントネイティブな選択肢です。特定のモデルプロバイダーに縛り付けるのではなく、<strong>あなたがすでに使っているコーディングエージェントの上で</strong>動作します：Claude Code、Codex、Cursor、Gemini、Copilot、OpenCode、そしてその他十数種類。単なる「bring your own key」ではなく「bring your own agent」です。</p>\n<p>一見の価値がある理由をいくつか挙げます：</p>\n<ul>\n<li><strong>オープンソース、Apache-2.0</strong> — クローンして、セルフホストして、全行を読めます。</li>\n<li><strong>ローカルで動作</strong> — プロジェクトは他人のクラウドではなく、自分のマシンの自分のフォルダに置かれます。</li>\n<li><strong>エージェントを差し替え可能</strong> — 21以上のコーディングエージェントに対応。生成を駆動するCLIは自分で選べます。</li>\n<li><strong>プロトタイプにとどまらない</strong> — プロトタイプ、ライブアーティファクト、スライドデッキ、マガジンレイアウト、画像生成、さらには動画まで、すべてを一つのワークスペースから。</li>\n<li><strong>豊富なデザインシステムとスキル</strong>を内蔵しているので、白紙のキャンバスから始める必要はありません。</li>\n</ul>\n<p>Claude Designを使ったことがあれば、見た目も使い心地もすぐに馴染むはずです — Open Designは意図的に同じ落ち着いた美学を保ちつつ、その上に機能を追加しています。</p>\n\n<h2>始める前に</h2>\n<p>Open Designのインストール方法は3通りあります。自分に合ったものを選んでください：</p>\n<table>\n<thead><tr><th>方法</th><th>向いている人</th><th>必要なもの</th></tr></thead>\n<tbody>\n<tr><td><strong>デスクトップアプリ</strong></td><td>ほとんどの人 — 設定不要</td><td>なし。ダウンロードして開くだけ。</td></tr>\n<tr><td><strong>ソースから実行</strong></td><td>コードを読みたい・改変したい開発者</td><td>Node <code>~24</code>、pnpm <code>10.33.x</code></td></tr>\n<tr><td><strong>エージェントに組み込む</strong></td><td>ターミナルで暮らしている人</td><td>既存のコーディングエージェントCLI</td></tr>\n</tbody>\n</table>\n<p>動画ではソースから実行する方法を使っていますが、現在<strong>おすすめなのはデスクトップアプリ</strong>です — Nodeもpnpmもクローンも不要です。</p>\n\n<h2>ステップ1 — Open Designをインストールする</h2>\n<h3>方法A — デスクトップアプリ（おすすめ、設定不要）</h3>\n<p><a href=\"https://open-design.ai/\">open-design.ai</a>にアクセスし、<strong>Download desktop</strong>をクリックします。macOS（Apple SiliconおよびIntel）、Windows（x64）、Linux（AppImage）向けのビルドが用意されています。インストール後、アプリは<code>PATH</code>上にあるコーディングエージェントCLIをすべて自動検出し、内蔵スキルとデザインシステムを読み込みます。</p>\n<h3>方法B — ソースから実行</h3>\n<p>動画のDennisのようにリポジトリから実行したい場合は、3つのコマンドだけで済みます：</p>\n<pre><code>git clone https://github.com/nexu-io/open-design.git\ncd open-design\ncorepack enable &amp;&amp; pnpm install\npnpm tools-dev run web</code></pre>\n<p>あとは表示されたローカルURLを開くだけです（Web UIは<code>http://localhost:7456</code>で動作します）。Node <code>~24</code>とpnpm <code>10.33.x</code>が必要ですが、Corepackが固定されたpnpmのバージョンを自動で選んでくれます。</p>\n<h3>方法C — コーディングエージェントに組み込む</h3>\n<p>GUIをまったく開かずに、エージェント内のスキルやMCPサーバーとしてOpen Designを呼び出したい場合は、次を実行します：</p>\n<pre><code>curl -fsSL https://open-design.ai/install.sh | sh -s &lt;agent&gt;\n# &lt;agent&gt; = claude | codex | cursor | copilot | gemini | opencode | …</code></pre>\n<p>あとはエージェント内でこう頼むだけです：<code>Use open-design to generate a landing page with the Linear design system</code>。</p>\n\n<h2>ステップ2 — 初回起動：コーディングエージェントを接続する</h2>\n<p>Open Designを初めて起動すると、マシンをスキャンして見つかったローカルCLIをすべて表示します — Claude Code、OpenCode、Copilot CLIなど。これが「bring your own agent」のステップです。</p>\n<ul>\n<li><strong>デフォルトのエージェントとモデルを選ぶ。</strong> インストール済みのCLIに生成を任せるか、このプロジェクト用に特定のモデル（たとえばClaude Opus）を指定します。</li>\n<li><strong>メディアプロバイダーを追加する（任意）。</strong> 画像、動画、音声を生成したいですか？OpenAI（gpt-image）、MiniMax、ElevenLabs、fal、Sunoなどのプロバイダー向けに自分のAPIキーを追加します。ここで「bring your own key」が活きてきます。</li>\n<li><strong>MCPサービスを接続する（任意）。</strong> エージェントに他のソースからデータを取得させたい場合は、Composioのようなコネクターを組み込みます。</li>\n<li><strong>スキルとデザインシステムを切り替える。</strong> 取り組む作業の種類に必要な機能だけを有効にします — プロトタイプ、スライドデッキ、モバイルアプリ、議事録など。</li>\n</ul>\n<p>これらはあとからいつでも変更できるので、初回はシンプルにしておきましょう。</p>\n\n<h2>ステップ3 — ワークスペースを探索する</h2>\n<p>Open Designは作業を<strong>プロジェクト単位</strong>で管理します：あるフォルダに対して実行すると、作成したデザインはそのプロジェクトディレクトリ内に保存されます。フォルダを切り替えれば、プロジェクトも切り替わります。</p>\n<p>プロジェクト内では、プロトタイプ、ライブアーティファクト、スライドデッキ、アニメーションを作成できます。プロトタイプでは2つの精細度から選べます：</p>\n<ul>\n<li><strong>ワイヤーフレーム</strong> — 骨組みだけ：ボックスや図形でレイアウトを素早く区切ります。</li>\n<li><strong>高精細</strong> — 構築中のページを完全にスタイリングしたプロトタイプ。</li>\n</ul>\n<p>Claude Designとの大きな違いの一つ：<strong>最初にデザインシステムを定義する必要がありません</strong>。Open Designは妥当なデフォルトと出発点のギャラリーを備えているので、既存のデザインシステムから始めることも、まったく使わずに始めることもできます。</p>\n<p><img src=\"/tutorials/open-design-in-20-minutes/03-design-systems.webp\" alt=\"Open Designのデザインシステムライブラリ — プレビューして再利用できる実在ブランドの出発点。\"></p>\n<p><em>デザインシステムライブラリ：実在ブランドの出発点（Agentic、Airbnb、Airtableなど）を、どのプロジェクトにもそのまま取り込めます。</em></p>\n<p>マーケットプレイスはブランドシステムにとどまりません。<strong>テンプレート</strong>ライブラリは、プロトタイプ、スライド、そして<strong>画像と動画</strong>の生成までカバーしています — タイプで絞り込んで、好きなものをフォークして出発点にできます。</p>\n<p><img src=\"/tutorials/open-design-in-20-minutes/04-templates.webp\" alt=\"プロトタイプ、画像、動画の出発点を備えたOpen Designのテンプレートライブラリ。\"></p>\n<p><em>テンプレート：プロトタイプ、スライド、画像、動画の出発点 — タイプで絞り込んでフォークすれば始められます。</em></p>\n<p>何かをインストールする前に、Web上の<a href=\"https://open-design.ai/plugins/\">open-design.ai/plugins</a>でプラグインライブラリ全体を閲覧できます。</p>\n\n<h2>ステップ4 — 最初のプロトタイプを作る</h2>\n<p>さあ、お楽しみの部分です。動画では、Dennisが既存のClaude Designプロジェクトをインポートし、Open Designに新しいページを作らせています。ここでも同じ流れをたどります：</p>\n<ol>\n<li><strong>新しいプロトタイプを作成する。</strong> 名前を付けて（Dennisは「Expensely」と名付けています）、<strong>高精細</strong>を選びます。</li>\n<li><strong>デザインシステムをインポートする。</strong> Open Designは既存のClaude DesignのZIPをインポートできるので、トークンやコンポーネントがそのまま引き継がれます。インポートされたデザインファイルは、ライブプレビューと並んでワークスペースに表示されます。</li>\n<li><strong>ブリーフを書く。</strong> Dennisは<em>「直近3か月のデータを使って12か月分の経費を予測する新しいページを作って」</em>とプロンプトを与えます。おなじみの分割レイアウトが表示されます：左に会話、右にプレビューとデザインファイル。</li>\n<li><strong>確認の質問に答える。</strong> エージェントが気の利いた追加質問をいくつか投げかけます — 同じ色でいいか？どの精細度か？シンプルな3か月平均でよいか？ — そのうえでToDoリストを立て、デザインシステムを読み込み、アーティファクト（<code>projections-v2.html</code>）を構築します。</li>\n<li><strong>デザインを反復改善する。</strong> 最初の出来に満足できませんか？別の方向性をリクエストしましょう。Dennisは「別の見た目と雰囲気にして」と頼み、<strong>エディトリアル</strong>な方向性を選んで、新たな<code>projections-v3</code>を得ます — 同じデータとデザインシステムから作られた、まったく別物のデザインです。</li>\n</ol>\n<p>出来上がるのは本物のインタラクティブなプロトタイプです：チャートやページをクリックして操作し、エクスポートしたり引き継いだりできます — すべてインポートしたデザインシステムから構築されています。</p>\n\n<h2>もっと使いこなすためのヒント</h2>\n<ul>\n<li>本物の見た目を確かめたいときは<strong>高精細から始め</strong>、構造を素早く区切りたいときはワイヤーフレームを使いましょう。</li>\n<li><strong>デザインはプロジェクトフォルダと一緒に残ります</strong> — 適切なディレクトリに対してOpen Designを実行することで作業を整理できます。</li>\n<li><strong>メディアキーは自前で用意し</strong>、実際に使うプロバイダーの分だけにしましょう。すべて揃える必要はありません。</li>\n<li><strong>始めるのにデザインシステムは不要です。</strong> 内蔵のものから始めても、Claude DesignのZIPをインポートしても、Open Designにデフォルトを推測させてもかまいません。</li>\n</ul>\n\n<h2>FAQ</h2>\n<p><strong>Open Designは無料ですか？</strong><br>はい — Apache-2.0ライセンスのオープンソースです。ローカルで無料で実行でき、課金が発生するのは接続したエージェントやメディアプロバイダーのモデル/API利用分だけです。</p>\n<p><strong>どのコーディングエージェントに対応していますか？</strong><br>Claude Code、Codex、Cursor、Gemini、GitHub Copilot、OpenCodeを含む21以上のエージェントです。Open DesignはマシンにすでにインストールされているCLIを検出します。</p>\n<p><strong>デザインする前にデザインシステムを作る必要がありますか？</strong><br>いいえ。Claude Designと違い、Open Designは使えるデフォルトと出発点のギャラリーを提供します。必要になったら自前のデザインシステムを持ち込めます。</p>\n<p><strong>Claude Designとはどう違いますか？</strong><br>おなじみの使い心地はそのままに、オープンソースでローカルファースト、エージェントを差し替え可能です — さらにスライドデッキ、マガジンレイアウト、画像生成、動画といった追加機能も備えています。</p>\n\n<hr>\n<p><em>この記事はCodingMenaceのファーストインプレッション解説をもとにしています。上の動画全編をご覧いただき、より多くのAIツール実機動画を見るには<a href=\"https://www.youtube.com/watch?v=QOqWZzecjuY\">CodingMenaceをチャンネル登録</a>してください。</em></p>",
    },
    "de": {
      title: "Open Design in 20 Minuten — Komplettes Setup + Demo",
      summary: "Ein vollständiger Einstieg von A bis Z — Open Design installieren, deinen Coding-Agent anbinden, den Workspace erkunden und deinen ersten High-Fidelity-Prototyp bauen. Basierend auf dem praxisnahen First-Impressions-Video von CodingMenace.",
      bodyHtml: "<p>Dieser Leitfaden führt dich durch deine ersten 20 Minuten mit Open Design — von der frischen Installation bis zum ersten generierten Prototyp. Er folgt dem Weg, den CodingMenace (Dennis) in <a href=\"https://www.youtube.com/watch?v=QOqWZzecjuY\">seinem praxisnahen First-Impressions-Video</a> gegangen ist, neu geschrieben und an die aktuelle Version angepasst, damit du Schritt für Schritt mitmachen kannst. Schau dir das Video oben für die Live-Demo an oder lies hier die schriftliche Fassung.</p>\n\n<p><img src=\"/tutorials/open-design-in-20-minutes/01-open-design-home.webp\" alt=\"Die Startseite von Open Design — eine quelloffene, lokale, agent-native Alternative zu Claude Design.\"></p>\n<p><em>Open Design positioniert sich als die quelloffene Alternative zu Claude Design — Desktop-first, agent-native, Apache-2.0.</em></p>\n\n<h2>Was ist Open Design?</h2>\n<p>Open Design ist eine quelloffene, local-first Design-Plattform — eine agent-native Alternative zu Claude Design und Figma. Statt dich an einen einzigen Modellanbieter zu binden, läuft es <strong>auf dem Coding-Agent, den du ohnehin schon nutzt</strong>: Claude Code, Codex, Cursor, Gemini, Copilot, OpenCode und ein Dutzend mehr. Es ist „bring your own agent“ statt nur bring your own key.</p>\n<p>Ein paar Dinge, die einen Blick wert sind:</p>\n<ul>\n<li><strong>Open Source, Apache-2.0</strong> — klonen, selbst hosten, jede Zeile lesen.</li>\n<li><strong>Läuft lokal</strong> — deine Projekte liegen in deinen eigenen Ordnern auf deinem Rechner, nicht in der Cloud von jemand anderem.</li>\n<li><strong>Agent-steckbar</strong> — über 21 Coding-Agents werden unterstützt; du wählst, welches CLI die Generierung antreibt.</li>\n<li><strong>Mehr als nur Prototypen</strong> — Prototypen, Live-Artefakte, Foliendecks, Magazin-Layouts, Bildgenerierung und sogar Video, alles aus einem einzigen Workspace.</li>\n<li><strong>Eine umfangreiche Bibliothek aus Design-Systemen und Skills</strong> integriert, sodass du nicht vor einer leeren Leinwand startest.</li>\n</ul>\n<p>Wenn du Claude Design schon einmal verwendet hast, kommt dir Optik und Bedienung sofort bekannt vor — Open Design behält bewusst dieselbe ruhige Ästhetik bei und ergänzt sie um neue Fähigkeiten.</p>\n\n<h2>Bevor du loslegst</h2>\n<p>Du hast drei Wege, Open Design zu installieren. Wähle den, der zu dir passt:</p>\n<table>\n<thead><tr><th>Weg</th><th>Am besten für</th><th>Voraussetzungen</th></tr></thead>\n<tbody>\n<tr><td><strong>Desktop-App</strong></td><td>Die meisten — keine Konfiguration nötig</td><td>Keine. Einfach herunterladen und öffnen.</td></tr>\n<tr><td><strong>Aus dem Quellcode starten</strong></td><td>Entwickler, die den Code lesen oder anpassen wollen</td><td>Node <code>~24</code>, pnpm <code>10.33.x</code></td></tr>\n<tr><td><strong>In deinen Agent installieren</strong></td><td>Leute, die im Terminal zu Hause sind</td><td>Ein vorhandenes Coding-Agent-CLI</td></tr>\n</tbody>\n</table>\n<p>Das Video nutzt den Weg über den Quellcode, doch die <strong>Desktop-App ist heute der empfohlene Weg</strong> — sie braucht weder Node noch pnpm noch ein Klonen.</p>\n\n<h2>Schritt 1 — Open Design installieren</h2>\n<h3>Variante A — Desktop-App (empfohlen, keine Konfiguration)</h3>\n<p>Gehe zu <a href=\"https://open-design.ai/\">open-design.ai</a> und klicke auf <strong>Download desktop</strong>. Builds sind für macOS (Apple Silicon und Intel), Windows (x64) und Linux (AppImage) verfügbar. Nach der Installation erkennt die App automatisch jedes Coding-Agent-CLI, das bereits in deinem <code>PATH</code> liegt, und lädt die integrierten Skills und Design-Systeme für dich.</p>\n<h3>Variante B — Aus dem Quellcode starten</h3>\n<p>Wenn du es lieber aus dem Repository startest — so wie Dennis im Video —, brauchst du nur drei Befehle:</p>\n<pre><code>git clone https://github.com/nexu-io/open-design.git\ncd open-design\ncorepack enable &amp;&amp; pnpm install\npnpm tools-dev run web</code></pre>\n<p>Öffne dann die lokale URL, die ausgegeben wird (die Web-Oberfläche läuft unter <code>http://localhost:7456</code>). Du brauchst Node <code>~24</code> und pnpm <code>10.33.x</code>; Corepack wählt die fest verankerte pnpm-Version automatisch für dich aus.</p>\n<h3>Variante C — In deinen Coding-Agent installieren</h3>\n<p>Um Open Design zu nutzen, ohne je die GUI zu öffnen — als Skill oder MCP-Server in deinem Agent aufgerufen —, führe aus:</p>\n<pre><code>curl -fsSL https://open-design.ai/install.sh | sh -s &lt;agent&gt;\n# &lt;agent&gt; = claude | codex | cursor | copilot | gemini | opencode | …</code></pre>\n<p>Bitte den Agent dann einfach: <code>Use open-design to generate a landing page with the Linear design system</code>.</p>\n\n<h2>Schritt 2 — Erster Start: deinen Coding-Agent anbinden</h2>\n<p>Beim ersten Start scannt Open Design deinen Rechner und zeigt dir jedes lokale CLI, das es gefunden hat — Claude Code, OpenCode, Copilot CLI und weitere. Das ist der „bring your own agent“-Schritt.</p>\n<ul>\n<li><strong>Wähle einen Standard-Agent und ein Modell.</strong> Lass das installierte CLI die Generierung antreiben oder erzwinge für dieses Projekt ein bestimmtes Modell (zum Beispiel Claude Opus).</li>\n<li><strong>Füge Medien-Anbieter hinzu (optional).</strong> Willst du Bilder, Video oder Audio generieren? Hinterlege deine eigenen API-Schlüssel für Anbieter wie OpenAI (gpt-image), MiniMax, ElevenLabs, fal, Suno und mehr. Hier kommt bring-your-own-key ins Spiel.</li>\n<li><strong>Verbinde MCP-Dienste (optional).</strong> Binde Connectoren wie Composio ein, wenn der Agent Daten aus anderen Quellen ziehen soll.</li>\n<li><strong>Schalte Skills und Design-Systeme an oder aus.</strong> Aktiviere nur die Fähigkeiten, die du für deine Art von Arbeit brauchst — Prototypen, Foliendecks, Mobile-Apps, Meeting-Notizen und so weiter.</li>\n</ul>\n<p>Du kannst all das später ändern, halte es beim ersten Durchgang also einfach.</p>\n\n<h2>Schritt 3 — Den Workspace erkunden</h2>\n<p>Open Design hält deine Arbeit <strong>projektbezogen</strong>: Wenn du es gegen einen Ordner ausführst, leben die Designs, die du erstellst, in diesem Projektverzeichnis. Wechselst du den Ordner, wechselst du das Projekt.</p>\n<p>Innerhalb eines Projekts kannst du Prototypen, Live-Artefakte, Foliendecks und Animationen erstellen. Bei Prototypen wählst du zwischen zwei Fidelitätsstufen:</p>\n<ul>\n<li><strong>Wireframe</strong> — die nackte Struktur: Kästchen und Formen, um das Layout schnell abzustecken.</li>\n<li><strong>High Fidelity</strong> — ein vollständig gestalteter Prototyp der Seite, die du baust.</li>\n</ul>\n<p>Ein wichtiger Unterschied zu Claude Design: Du musst <strong>nicht zuerst ein Design-System definieren</strong>. Open Design bringt sinnvolle Voreinstellungen und eine Galerie von Startpunkten mit, sodass du von einem bestehenden Design-System aus loslegen kannst — oder von gar keinem.</p>\n<p><img src=\"/tutorials/open-design-in-20-minutes/03-design-systems.webp\" alt=\"Die Design-System-Bibliothek von Open Design — echte Marken-Startpunkte, die du in der Vorschau ansehen und wiederverwenden kannst.\"></p>\n<p><em>Die Design-System-Bibliothek: reale Marken-Startpunkte (Agentic, Airbnb, Airtable und mehr), die du in jedes Projekt einrasten lassen kannst.</em></p>\n<p>Der Marktplatz geht weit über Marken-Systeme hinaus. Die <strong>Templates</strong>-Bibliothek deckt Prototypen, Folien sowie die Generierung von <strong>Bild und Video</strong> ab — filtere nach Typ und forke ein beliebiges als deinen Ausgangspunkt.</p>\n<p><img src=\"/tutorials/open-design-in-20-minutes/04-templates.webp\" alt=\"Die Templates-Bibliothek von Open Design mit Startpunkten für Prototyp, Bild und Video.\"></p>\n<p><em>Templates: Startpunkte für Prototyp, Folie, Bild und Video — filtere nach Typ und forke, um loszulegen.</em></p>\n<p>Die komplette Plugin-Bibliothek kannst du im Web unter <a href=\"https://open-design.ai/plugins/\">open-design.ai/plugins</a> durchstöbern, bevor du irgendetwas installierst.</p>\n\n<h2>Schritt 4 — Deinen ersten Prototyp bauen</h2>\n<p>Jetzt kommt der spaßige Teil. Im Video importiert Dennis ein bestehendes Claude-Design-Projekt und lässt Open Design eine neue Seite dafür bauen. Hier ist derselbe Ablauf:</p>\n<ol>\n<li><strong>Lege einen neuen Prototyp an.</strong> Gib ihm einen Namen (Dennis nennt seinen „Expensely“) und wähle <strong>High Fidelity</strong>.</li>\n<li><strong>Importiere dein Design-System.</strong> Open Design kann ein bestehendes Claude-Design-ZIP importieren, sodass deine Tokens und Komponenten mitkommen. Die importierten Design-Dateien erscheinen im Workspace neben einer Live-Vorschau.</li>\n<li><strong>Schreibe das Briefing.</strong> Dennis fordert es auf: <em>„create a new page projecting expenses for 12 months using the previous 3 months.“</em> Du bekommst das vertraute geteilte Layout: das Gespräch links, Vorschau und Design-Dateien rechts.</li>\n<li><strong>Beantworte die Rückfragen.</strong> Der Agent stellt ein paar clevere Nachfragen — gleiche Farben? welche Fidelitätsstufe? einfacher 3-Monats-Durchschnitt? — plant dann eine To-do-Liste, liest das Design-System und baut das Artefakt (<code>projections-v2.html</code>).</li>\n<li><strong>Iteriere am Design.</strong> Mit dem ersten Wurf nicht zufrieden? Bitte um eine andere Richtung. Dennis fragt nach „a different look and feel“, wählt eine <strong>editoriale</strong> Richtung und erhält ein frisches <code>projections-v3</code> — ein wirklich anderes Design, gebaut aus denselben Daten und demselben Design-System.</li>\n</ol>\n<p>Das Ergebnis ist ein echter, interaktiver Prototyp: Klicke dich durch die Charts und Seiten, dann exportiere oder übergib — alles gebaut aus dem Design-System, das du importiert hast.</p>\n\n<h2>Tipps, um mehr herauszuholen</h2>\n<ul>\n<li><strong>Starte mit High Fidelity</strong>, wenn du das echte Ergebnis sehen willst; nutze Wireframe, um die Struktur schnell abzustecken.</li>\n<li><strong>Deine Designs bleiben beim Projektordner</strong> — organisiere deine Arbeit, indem du Open Design gegen das richtige Verzeichnis ausführst.</li>\n<li><strong>Hinterlege deine eigenen Medien-Schlüssel</strong> nur für die Anbieter, die du tatsächlich nutzt; du brauchst nicht alle.</li>\n<li><strong>Du brauchst kein Design-System, um zu starten.</strong> Beginne mit einem integrierten, importiere ein Claude-Design-ZIP oder lass Open Design Voreinstellungen ableiten.</li>\n</ul>\n\n<h2>FAQ</h2>\n<p><strong>Ist Open Design kostenlos?</strong><br>Ja — es ist Open Source unter der Apache-2.0-Lizenz. Du kannst es kostenlos lokal betreiben; du zahlst nur für die Modell-/API-Nutzung des jeweiligen Agents und der Medien-Anbieter, die du anbindest.</p>\n<p><strong>Welche Coding-Agents werden unterstützt?</strong><br>Über 21 Agents, darunter Claude Code, Codex, Cursor, Gemini, GitHub Copilot und OpenCode. Open Design erkennt die CLIs, die bereits auf deinem Rechner installiert sind.</p>\n<p><strong>Muss ich ein Design-System erstellen, bevor ich designen kann?</strong><br>Nein. Anders als Claude Design gibt dir Open Design funktionierende Voreinstellungen und eine Galerie von Startpunkten. Du kannst dein eigenes Design-System mitbringen, wenn du eines willst.</p>\n<p><strong>Wie unterscheidet es sich von Claude Design?</strong><br>Gleiches vertrautes Gefühl, aber Open Source, local-first und agent-steckbar — plus zusätzliche Fähigkeiten wie Foliendecks, Magazin-Layouts, Bildgenerierung und Video.</p>\n\n<hr>\n<p><em>Dieser schriftliche Leitfaden basiert auf dem First-Impressions-Walkthrough von CodingMenace. Schau dir das vollständige Video oben an und <a href=\"https://www.youtube.com/watch?v=QOqWZzecjuY\">abonniere CodingMenace</a> für weitere praxisnahe Videos zu KI-Tools.</em></p>",
    },
    "fr": {
      title: "Open Design en 20 minutes — installation complète et démo",
      summary: "Un guide de démarrage complet : installez Open Design, connectez votre coding agent, explorez l'espace de travail et créez votre premier prototype haute fidélité. D'après la vidéo de premières impressions en pratique de CodingMenace.",
      bodyHtml: "<p>Ce guide vous accompagne pendant vos 20 premières minutes avec Open Design — de l'installation à zéro jusqu'à votre premier prototype généré. Il reprend le parcours suivi par CodingMenace (Dennis) dans <a href=\"https://www.youtube.com/watch?v=QOqWZzecjuY\">sa vidéo de premières impressions en pratique</a>, réécrit et mis à jour pour coller à la version actuelle afin que vous puissiez suivre étape par étape. Regardez la vidéo ci-dessus pour la démonstration en direct, ou poursuivez la lecture pour la version écrite.</p>\n\n<p><img src=\"/tutorials/open-design-in-20-minutes/01-open-design-home.webp\" alt=\"La page d'accueil d'Open Design — une alternative à Claude Design open source, locale et agent-native.\"></p>\n<p><em>Open Design se positionne comme l'alternative open source à Claude Design — pensée pour le desktop, agent-native, sous licence Apache-2.0.</em></p>\n\n<h2>Qu'est-ce qu'Open Design ?</h2>\n<p>Open Design est une plateforme de design open source et local-first — une alternative agent-native à Claude Design et à Figma. Plutôt que de vous enfermer chez un seul fournisseur de modèle, elle s'appuie <strong>sur le coding agent que vous utilisez déjà</strong> : Claude Code, Codex, Cursor, Gemini, Copilot, OpenCode et une douzaine d'autres. C'est du « bring your own agent », et pas seulement du bring your own key.</p>\n<p>Quelques raisons d'y jeter un œil :</p>\n<ul>\n<li><strong>Open source, Apache-2.0</strong> — clonez-le, auto-hébergez-le, lisez chaque ligne.</li>\n<li><strong>Fonctionne en local</strong> — vos projets vivent dans vos propres dossiers, sur votre machine, pas dans le cloud de quelqu'un d'autre.</li>\n<li><strong>Agents interchangeables</strong> — plus de 21 coding agents sont pris en charge ; vous choisissez quel CLI pilote la génération.</li>\n<li><strong>Bien plus que des prototypes</strong> — prototypes, artefacts interactifs, présentations, mises en page de type magazine, génération d'images et même de vidéos, le tout depuis un seul espace de travail.</li>\n<li><strong>Une vaste bibliothèque de design systems et de skills</strong> intégrés, pour ne pas partir d'une page blanche.</li>\n</ul>\n<p>Si vous avez déjà utilisé Claude Design, l'environnement vous sera immédiatement familier — Open Design conserve volontairement la même esthétique épurée, puis ajoute des capacités par-dessus.</p>\n\n<h2>Avant de commencer</h2>\n<p>Vous avez trois façons d'installer Open Design. Choisissez celle qui vous convient :</p>\n<table>\n<thead><tr><th>Méthode</th><th>Idéale pour</th><th>Prérequis</th></tr></thead>\n<tbody>\n<tr><td><strong>Application desktop</strong></td><td>La plupart des gens — zéro configuration</td><td>Aucun. Téléchargez et ouvrez, c'est tout.</td></tr>\n<tr><td><strong>Exécution depuis les sources</strong></td><td>Les développeurs qui veulent lire ou modifier le code</td><td>Node <code>~24</code>, pnpm <code>10.33.x</code></td></tr>\n<tr><td><strong>Installation dans votre agent</strong></td><td>Ceux qui vivent dans le terminal</td><td>Un CLI de coding agent déjà installé</td></tr>\n</tbody>\n</table>\n<p>La vidéo utilise l'exécution depuis les sources, mais l'<strong>application desktop est aujourd'hui la voie recommandée</strong> — elle ne nécessite ni Node, ni pnpm, ni clonage.</p>\n\n<h2>Étape 1 — Installer Open Design</h2>\n<h3>Option A — Application desktop (recommandée, zéro configuration)</h3>\n<p>Rendez-vous sur <a href=\"https://open-design.ai/\">open-design.ai</a> et cliquez sur <strong>Download desktop</strong>. Des builds sont disponibles pour macOS (Apple Silicon et Intel), Windows (x64) et Linux (AppImage). Après l'installation, l'application détecte automatiquement tous les CLI de coding agent déjà présents dans votre <code>PATH</code> et charge pour vous les skills et design systems intégrés.</p>\n<h3>Option B — Exécution depuis les sources</h3>\n<p>Si vous préférez l'exécuter depuis le dépôt — comme le fait Dennis dans la vidéo — il vous suffit de trois commandes :</p>\n<pre><code>git clone https://github.com/nexu-io/open-design.git\ncd open-design\ncorepack enable &amp;&amp; pnpm install\npnpm tools-dev run web</code></pre>\n<p>Ouvrez ensuite l'URL locale qui s'affiche (l'interface web tourne sur <code>http://localhost:7456</code>). Vous avez besoin de Node <code>~24</code> et de pnpm <code>10.33.x</code> ; Corepack sélectionnera pour vous la version de pnpm épinglée.</p>\n<h3>Option C — Installation dans votre coding agent</h3>\n<p>Pour utiliser Open Design sans jamais ouvrir l'interface graphique — en l'appelant comme un skill ou un serveur MCP au sein de votre agent — exécutez :</p>\n<pre><code>curl -fsSL https://open-design.ai/install.sh | sh -s &lt;agent&gt;\n# &lt;agent&gt; = claude | codex | cursor | copilot | gemini | opencode | …</code></pre>\n<p>Ensuite, depuis l'agent, demandez simplement : <code>Use open-design to generate a landing page with the Linear design system</code>.</p>\n\n<h2>Étape 2 — Premier lancement : connecter votre coding agent</h2>\n<p>Au premier lancement d'Open Design, l'application analyse votre machine et vous présente tous les CLI locaux trouvés — Claude Code, OpenCode, Copilot CLI, et d'autres. C'est l'étape « bring your own agent ».</p>\n<ul>\n<li><strong>Choisissez un agent et un modèle par défaut.</strong> Laissez le CLI installé piloter la génération, ou imposez un modèle précis (par exemple Claude Opus) pour ce projet.</li>\n<li><strong>Ajoutez des fournisseurs de médias (facultatif).</strong> Vous voulez générer des images, des vidéos ou de l'audio ? Ajoutez vos propres clés API pour des fournisseurs comme OpenAI (gpt-image), MiniMax, ElevenLabs, fal, Suno, et bien d'autres. C'est ici qu'intervient le bring-your-own-key.</li>\n<li><strong>Connectez des services MCP (facultatif).</strong> Branchez des connecteurs comme Composio si vous voulez que l'agent récupère des données depuis d'autres sources.</li>\n<li><strong>Activez les skills et design systems.</strong> N'activez que les capacités nécessaires au type de travail que vous faites — prototypes, présentations, applications mobiles, comptes rendus de réunion, etc.</li>\n</ul>\n<p>Vous pourrez modifier tout cela plus tard, alors faites simple lors du premier passage.</p>\n\n<h2>Étape 3 — Explorer l'espace de travail</h2>\n<p>Open Design garde votre travail <strong>cantonné au projet</strong> : lorsque vous l'exécutez sur un dossier, les designs que vous créez vivent à l'intérieur de ce répertoire de projet. Changez de dossier et vous changez de projet.</p>\n<p>Au sein d'un projet, vous pouvez créer des prototypes, des artefacts interactifs, des présentations et des animations. Pour les prototypes, vous choisissez entre deux niveaux de fidélité :</p>\n<ul>\n<li><strong>Wireframe</strong> — la structure brute : des cadres et des formes pour esquisser rapidement la mise en page.</li>\n<li><strong>Haute fidélité</strong> — un prototype complet et stylé de la page que vous construisez.</li>\n</ul>\n<p>Une différence majeure avec Claude Design : vous n'êtes <strong>pas obligé de définir d'abord un design system</strong>. Open Design fournit des valeurs par défaut pertinentes et une galerie de points de départ, si bien que vous pouvez partir d'un design system existant — ou d'aucun.</p>\n<p><img src=\"/tutorials/open-design-in-20-minutes/03-design-systems.webp\" alt=\"La bibliothèque de design systems d'Open Design — des points de départ de marques réelles que vous pouvez prévisualiser et réutiliser.\"></p>\n<p><em>La bibliothèque de design systems : des points de départ issus de marques réelles (Agentic, Airbnb, Airtable, et plus) que vous pouvez intégrer à n'importe quel projet.</em></p>\n<p>Le marketplace va bien au-delà des systèmes de marque. La bibliothèque de <strong>templates</strong> couvre les prototypes, les présentations et la génération d'<strong>images comme de vidéos</strong> — filtrez par type et forkez celui que vous voulez comme point de départ.</p>\n<p><img src=\"/tutorials/open-design-in-20-minutes/04-templates.webp\" alt=\"La bibliothèque de templates d'Open Design, avec des points de départ pour prototypes, images et vidéos.\"></p>\n<p><em>Templates : des points de départ pour prototypes, présentations, images et vidéos — filtrez par type et forkez pour commencer.</em></p>\n<p>Vous pouvez parcourir l'ensemble de la bibliothèque de plugins sur le web depuis <a href=\"https://open-design.ai/plugins/\">open-design.ai/plugins</a> avant d'installer quoi que ce soit.</p>\n\n<h2>Étape 4 — Créer votre premier prototype</h2>\n<p>Place à la partie amusante. Dans la vidéo, Dennis importe un projet Claude Design existant et demande à Open Design de lui créer une nouvelle page. Voici le même déroulé :</p>\n<ol>\n<li><strong>Créez un nouveau prototype.</strong> Donnez-lui un nom (Dennis appelle le sien « Expensely ») et choisissez <strong>Haute fidélité</strong>.</li>\n<li><strong>Importez votre design system.</strong> Open Design peut importer un ZIP Claude Design existant, afin que vos tokens et composants soient repris. Les fichiers de design importés apparaissent dans l'espace de travail aux côtés d'un aperçu en direct.</li>\n<li><strong>Rédigez le brief.</strong> Dennis lui demande de <em>« create a new page projecting expenses for 12 months using the previous 3 months »</em>. Vous obtenez la disposition en deux volets désormais familière : la conversation à gauche, l'aperçu et les fichiers de design à droite.</li>\n<li><strong>Répondez aux questions de clarification.</strong> L'agent pose quelques questions de suivi pertinentes — mêmes couleurs ? quelle fidélité ? simple moyenne sur 3 mois ? — puis établit une liste de tâches, lit le design system et construit l'artefact (<code>projections-v2.html</code>).</li>\n<li><strong>Itérez sur le design.</strong> Le premier jet ne vous satisfait pas ? Demandez une autre direction. Dennis réclame « a different look and feel », choisit une direction <strong>éditoriale</strong> et obtient un nouveau <code>projections-v3</code> — un design véritablement différent, construit à partir des mêmes données et du même design system.</li>\n</ol>\n<p>Le résultat est un prototype réel et interactif : parcourez les graphiques et les pages, puis exportez ou transmettez — le tout construit à partir du design system que vous avez importé.</p>\n\n<h2>Conseils pour en tirer le meilleur parti</h2>\n<ul>\n<li><strong>Commencez en haute fidélité</strong> quand vous voulez voir le rendu réel ; utilisez le wireframe pour esquisser rapidement la structure.</li>\n<li><strong>Vos designs restent attachés au dossier du projet</strong> — organisez votre travail en exécutant Open Design sur le bon répertoire.</li>\n<li><strong>N'apportez vos propres clés médias</strong> que pour les fournisseurs que vous utilisez réellement ; vous n'avez pas besoin de toutes.</li>\n<li><strong>Vous n'avez pas besoin d'un design system pour démarrer.</strong> Partez d'un système intégré, importez un ZIP Claude Design, ou laissez Open Design déduire des valeurs par défaut.</li>\n</ul>\n\n<h2>FAQ</h2>\n<p><strong>Open Design est-il gratuit ?</strong><br>Oui — c'est un logiciel open source sous licence Apache-2.0. Vous pouvez l'exécuter gratuitement en local ; vous ne payez que l'usage du modèle/de l'API de l'agent et des fournisseurs de médias que vous connectez.</p>\n<p><strong>Quels coding agents prend-il en charge ?</strong><br>Plus de 21 agents, dont Claude Code, Codex, Cursor, Gemini, GitHub Copilot et OpenCode. Open Design détecte les CLI déjà installés sur votre machine.</p>\n<p><strong>Dois-je créer un design system avant de pouvoir concevoir ?</strong><br>Non. Contrairement à Claude Design, Open Design vous fournit des valeurs par défaut opérationnelles et une galerie de points de départ. Vous pourrez apporter votre propre design system quand vous en voudrez un.</p>\n<p><strong>En quoi se distingue-t-il de Claude Design ?</strong><br>Le même environnement familier, mais open source, local-first et compatible avec les agents — auxquels s'ajoutent des capacités supplémentaires comme les présentations, les mises en page de type magazine, la génération d'images et la vidéo.</p>\n\n<hr>\n<p><em>Ce guide écrit s'appuie sur la démonstration de premières impressions de CodingMenace. Regardez la vidéo complète ci-dessus, et <a href=\"https://www.youtube.com/watch?v=QOqWZzecjuY\">abonnez-vous à CodingMenace</a> pour plus de vidéos pratiques sur les outils d'IA.</em></p>",
    },
    "ru": {
      title: "Open Design за 20 минут — полная установка и демо",
      summary: "Полное руководство для начинающих: установите Open Design, подключите своего кодинг-агента, осмотрите рабочее пространство и соберите свой первый высокодетализированный прототип. По мотивам обзорного видео CodingMenace с практическим первым знакомством.",
      bodyHtml: "<p>Это руководство проведёт вас через первые 20 минут работы с Open Design — от чистой установки до первого сгенерированного прототипа. Оно повторяет путь, который CodingMenace (Деннис) прошёл в <a href=\"https://www.youtube.com/watch?v=QOqWZzecjuY\">своём обзорном видео с практическим первым знакомством</a>, но переписано и обновлено под текущий релиз, чтобы вы могли шаг за шагом всё повторить. Посмотрите видео выше, чтобы увидеть процесс вживую, либо читайте дальше текстовую версию.</p>\n\n<p><img src=\"/tutorials/open-design-in-20-minutes/01-open-design-home.webp\" alt=\"Главная страница Open Design — открытая, локальная, agent-native альтернатива Claude Design.\"></p>\n<p><em>Open Design позиционирует себя как открытая альтернатива Claude Design — desktop-first, agent-native, Apache-2.0.</em></p>\n\n<h2>Что такое Open Design?</h2>\n<p>Open Design — это открытая платформа для дизайна, работающая прежде всего локально, — agent-native альтернатива Claude Design и Figma. Вместо того чтобы привязывать вас к одному поставщику моделей, она работает <strong>поверх того кодинг-агента, которым вы уже пользуетесь</strong>: Claude Code, Codex, Cursor, Gemini, Copilot, OpenCode и ещё десяток других. Это принцип «принеси своего агента», а не просто «принеси свой ключ».</p>\n<p>Несколько причин присмотреться к ней:</p>\n<ul>\n<li><strong>Открытый исходный код, Apache-2.0</strong> — клонируйте, разворачивайте у себя, читайте каждую строку.</li>\n<li><strong>Работает локально</strong> — ваши проекты лежат в собственных папках на вашей машине, а не в чужом облаке.</li>\n<li><strong>Подключаемые агенты</strong> — поддерживается 21+ кодинг-агент; вы сами выбираете, какой CLI управляет генерацией.</li>\n<li><strong>Больше, чем прототипы</strong> — прототипы, живые артефакты, презентации, журнальные вёрстки, генерация изображений и даже видео — всё в одном рабочем пространстве.</li>\n<li><strong>Большая библиотека дизайн-систем и навыков</strong> встроена, так что вы стартуете не с чистого листа.</li>\n</ul>\n<p>Если вы работали с Claude Design, интерфейс покажется мгновенно знакомым — Open Design намеренно сохраняет ту же спокойную эстетику, а сверху добавляет новые возможности.</p>\n\n<h2>Перед тем как начать</h2>\n<p>Установить Open Design можно тремя способами. Выберите тот, что подходит именно вам:</p>\n<table>\n<thead><tr><th>Способ</th><th>Кому подойдёт</th><th>Требования</th></tr></thead>\n<tbody>\n<tr><td><strong>Десктопное приложение</strong></td><td>Большинству — без настройки</td><td>Ничего. Просто скачайте и откройте.</td></tr>\n<tr><td><strong>Запуск из исходников</strong></td><td>Разработчикам, которые хотят читать или править код</td><td>Node <code>~24</code>, pnpm <code>10.33.x</code></td></tr>\n<tr><td><strong>Установка внутрь агента</strong></td><td>Тем, кто живёт в терминале</td><td>Уже установленный CLI кодинг-агента</td></tr>\n</tbody>\n</table>\n<p>В видео используется запуск из исходников, но сегодня <strong>рекомендуемый способ — десктопное приложение</strong>: ему не нужны ни Node, ни pnpm, ни клонирование репозитория.</p>\n\n<h2>Шаг 1 — Установка Open Design</h2>\n<h3>Вариант A — Десктопное приложение (рекомендуется, без настройки)</h3>\n<p>Зайдите на <a href=\"https://open-design.ai/\">open-design.ai</a> и нажмите <strong>Download desktop</strong>. Сборки доступны для macOS (Apple Silicon и Intel), Windows (x64) и Linux (AppImage). После установки приложение автоматически находит все CLI кодинг-агентов, уже доступные в вашем <code>PATH</code>, и подгружает встроенные навыки и дизайн-системы.</p>\n<h3>Вариант B — Запуск из исходников</h3>\n<p>Если вы предпочитаете запускать всё прямо из репозитория — как делает Деннис в видео, — понадобятся всего три команды:</p>\n<pre><code>git clone https://github.com/nexu-io/open-design.git\ncd open-design\ncorepack enable &amp;&amp; pnpm install\npnpm tools-dev run web</code></pre>\n<p>Затем откройте локальный URL, который она напечатает (веб-интерфейс работает по адресу <code>http://localhost:7456</code>). Вам нужны Node <code>~24</code> и pnpm <code>10.33.x</code>; Corepack сам выберет закреплённую версию pnpm.</p>\n<h3>Вариант C — Установка внутрь кодинг-агента</h3>\n<p>Чтобы пользоваться Open Design, ни разу не открывая GUI — вызывая его как навык или MCP-сервер внутри агента, — выполните:</p>\n<pre><code>curl -fsSL https://open-design.ai/install.sh | sh -s &lt;agent&gt;\n# &lt;agent&gt; = claude | codex | cursor | copilot | gemini | opencode | …</code></pre>\n<p>После этого внутри агента достаточно попросить: <code>Use open-design to generate a landing page with the Linear design system</code>.</p>\n\n<h2>Шаг 2 — Первый запуск: подключаем кодинг-агента</h2>\n<p>При первом запуске Open Design сканирует вашу машину и показывает все найденные локальные CLI — Claude Code, OpenCode, Copilot CLI и другие. Это и есть шаг «принеси своего агента».</p>\n<ul>\n<li><strong>Выберите агента и модель по умолчанию.</strong> Дайте установленному CLI управлять генерацией или жёстко задайте конкретную модель (например, Claude Opus) для этого проекта.</li>\n<li><strong>Добавьте медиа-провайдеров (необязательно).</strong> Хотите генерировать изображения, видео или аудио? Добавьте собственные API-ключи провайдеров вроде OpenAI (gpt-image), MiniMax, ElevenLabs, fal, Suno и других. Вот тут и пригодится принцип «принеси свой ключ».</li>\n<li><strong>Подключите MCP-сервисы (необязательно).</strong> Подцепите коннекторы вроде Composio, если хотите, чтобы агент подтягивал данные из других источников.</li>\n<li><strong>Включите нужные навыки и дизайн-системы.</strong> Активируйте только те возможности, которые нужны под вашу задачу — прототипы, презентации, мобильные приложения, заметки со встреч и так далее.</li>\n</ul>\n<p>Всё это можно изменить позже, поэтому на первом проходе не усложняйте.</p>\n\n<h2>Шаг 3 — Знакомство с рабочим пространством</h2>\n<p>Open Design держит вашу работу <strong>в рамках проекта</strong>: когда вы запускаете его в какой-то папке, созданные дизайны живут внутри этого каталога проекта. Сменили папку — сменили проект.</p>\n<p>Внутри проекта можно создавать прототипы, живые артефакты, презентации и анимации. Для прототипов вы выбираете один из двух уровней детализации:</p>\n<ul>\n<li><strong>Wireframe</strong> — голый каркас: прямоугольники и фигуры, чтобы быстро набросать раскладку.</li>\n<li><strong>High fidelity</strong> — полноценный, оформленный прототип страницы, которую вы собираете.</li>\n</ul>\n<p>Одно ключевое отличие от Claude Design: вас <strong>не заставляют сначала определять дизайн-систему</strong>. Open Design идёт с разумными значениями по умолчанию и галереей отправных точек, так что начать можно как с готовой дизайн-системы, так и вовсе без неё.</p>\n<p><img src=\"/tutorials/open-design-in-20-minutes/03-design-systems.webp\" alt=\"Библиотека дизайн-систем Open Design — реальные брендовые отправные точки, которые можно посмотреть и переиспользовать.\"></p>\n<p><em>Библиотека дизайн-систем: отправные точки на основе реальных брендов (Agentic, Airbnb, Airtable и другие), которые можно подключить к любому проекту.</em></p>\n<p>Маркетплейс выходит далеко за рамки брендовых систем. Библиотека <strong>шаблонов</strong> охватывает прототипы, слайды, а также генерацию <strong>изображений и видео</strong> — фильтруйте по типу и форкайте любой как отправную точку.</p>\n<p><img src=\"/tutorials/open-design-in-20-minutes/04-templates.webp\" alt=\"Библиотека шаблонов Open Design с отправными точками для прототипов, изображений и видео.\"></p>\n<p><em>Шаблоны: отправные точки для прототипов, слайдов, изображений и видео — фильтруйте по типу и форкайте, чтобы начать.</em></p>\n<p>Просмотреть всю библиотеку плагинов можно прямо в вебе по адресу <a href=\"https://open-design.ai/plugins/\">open-design.ai/plugins</a> ещё до того, как что-либо устанавливать.</p>\n\n<h2>Шаг 4 — Собираем первый прототип</h2>\n<p>А теперь самое интересное. В видео Деннис импортирует существующий проект Claude Design и просит Open Design построить для него новую страницу. Вот тот же сценарий:</p>\n<ol>\n<li><strong>Создайте новый прототип.</strong> Дайте ему имя (Деннис называет свой «Expensely») и выберите <strong>High fidelity</strong>.</li>\n<li><strong>Импортируйте дизайн-систему.</strong> Open Design умеет импортировать существующий ZIP из Claude Design, так что ваши токены и компоненты переносятся целиком. Импортированные файлы дизайна появляются в рабочем пространстве рядом с живым превью.</li>\n<li><strong>Напишите бриф.</strong> Деннис просит её <em>«создать новую страницу, прогнозирующую расходы на 12 месяцев на основе предыдущих 3 месяцев».</em> Вы получаете привычную раздельную раскладку: диалог слева, превью и файлы дизайна справа.</li>\n<li><strong>Ответьте на уточняющие вопросы.</strong> Агент задаёт несколько разумных уточнений — те же цвета? какой уровень детализации? простое среднее за 3 месяца? — затем составляет список задач, читает дизайн-систему и собирает артефакт (<code>projections-v2.html</code>).</li>\n<li><strong>Дорабатывайте дизайн.</strong> Не устроил первый вариант? Попросите другое направление. Деннис просит «другой внешний вид и подачу», выбирает <strong>редакционное (editorial)</strong> направление и получает свежий <code>projections-v3</code> — действительно иной дизайн, построенный на тех же данных и той же дизайн-системе.</li>\n</ol>\n<p>В результате — настоящий интерактивный прототип: кликайте по графикам и страницам, а потом экспортируйте или передавайте дальше — и всё это собрано на основе импортированной вами дизайн-системы.</p>\n\n<h2>Советы, как выжать из неё больше</h2>\n<ul>\n<li><strong>Начинайте с high fidelity</strong>, когда хотите увидеть всё в реальном виде; используйте wireframe, чтобы быстро набросать структуру.</li>\n<li><strong>Ваши дизайны остаются в папке проекта</strong> — организуйте работу, запуская Open Design в нужном каталоге.</li>\n<li><strong>Подключайте собственные медиа-ключи</strong> только для тех провайдеров, которыми реально пользуетесь; все сразу не нужны.</li>\n<li><strong>Дизайн-система для старта не обязательна.</strong> Начните со встроенной, импортируйте ZIP из Claude Design или дайте Open Design подобрать значения по умолчанию.</li>\n</ul>\n\n<h2>Частые вопросы</h2>\n<p><strong>Open Design бесплатен?</strong><br>Да — это открытый исходный код под лицензией Apache-2.0. Запускать его локально можно бесплатно; вы платите только за использование моделей/API тех агентов и медиа-провайдеров, которых подключаете.</p>\n<p><strong>Какие кодинг-агенты он поддерживает?</strong><br>21+ агент, включая Claude Code, Codex, Cursor, Gemini, GitHub Copilot и OpenCode. Open Design сам находит CLI, уже установленные на вашей машине.</p>\n<p><strong>Обязательно ли создавать дизайн-систему, прежде чем приступить к дизайну?</strong><br>Нет. В отличие от Claude Design, Open Design даёт вам рабочие значения по умолчанию и галерею отправных точек. Свою дизайн-систему можно принести тогда, когда она вам понадобится.</p>\n<p><strong>Чем он отличается от Claude Design?</strong><br>Та же знакомая подача, но открытый код, локальная работа в первую очередь и подключаемые агенты — плюс дополнительные возможности вроде презентаций, журнальных вёрсток, генерации изображений и видео.</p>\n\n<hr>\n<p><em>Это текстовое руководство основано на обзоре с первым знакомством от CodingMenace. Посмотрите видео целиком выше и <a href=\"https://www.youtube.com/watch?v=QOqWZzecjuY\">подпишитесь на CodingMenace</a>, чтобы смотреть больше практических видео об AI-инструментах.</em></p>",
    },
    "es": {
      title: "Open Design en 20 minutos: instalación completa y demo",
      summary: "Una guía de iniciación completa: instala Open Design, conecta tu agente de programación, recorre el espacio de trabajo y crea tu primer prototipo de alta fidelidad. Basada en el vídeo de primeras impresiones de CodingMenace.",
      bodyHtml: "<p>Esta guía te acompaña en tus primeros 20 minutos con Open Design, desde una instalación limpia hasta tu primer prototipo generado. Sigue el camino que tomó CodingMenace (Dennis) en <a href=\"https://www.youtube.com/watch?v=QOqWZzecjuY\">su vídeo de primeras impresiones</a>, reescrito y actualizado para coincidir con la versión actual, de modo que puedas seguirlo paso a paso. Mira el vídeo de arriba para ver el recorrido en directo, o sigue leyendo para la versión escrita.</p>\n\n<p><img src=\"/tutorials/open-design-in-20-minutes/01-open-design-home.webp\" alt=\"La página de inicio de Open Design: una alternativa a Claude Design open source, local y nativa de agentes.\"></p>\n<p><em>Open Design se posiciona como la alternativa open source a Claude Design: orientada al escritorio, nativa de agentes y con licencia Apache-2.0.</em></p>\n\n<h2>¿Qué es Open Design?</h2>\n<p>Open Design es una plataforma de diseño open source y local-first, una alternativa nativa de agentes a Claude Design y Figma. En lugar de atarte a un único proveedor de modelos, funciona <strong>sobre el agente de programación que ya usas</strong>: Claude Code, Codex, Cursor, Gemini, Copilot, OpenCode y una decena más. Es «trae tu propio agente», no solo trae tu propia clave.</p>\n<p>Algunas cosas por las que merece la pena echarle un vistazo:</p>\n<ul>\n<li><strong>Open source, Apache-2.0</strong>: clónalo, alójalo tú mismo, lee cada línea.</li>\n<li><strong>Se ejecuta en local</strong>: tus proyectos viven en tus propias carpetas, en tu máquina, no en la nube de otra persona.</li>\n<li><strong>Agentes intercambiables</strong>: se admiten más de 21 agentes de programación; tú eliges qué CLI impulsa la generación.</li>\n<li><strong>Mucho más que prototipos</strong>: prototipos, artefactos en vivo, presentaciones, maquetas tipo revista, generación de imágenes e incluso vídeo, todo desde un mismo espacio de trabajo.</li>\n<li><strong>Una amplia biblioteca de sistemas de diseño y skills</strong> integrados, para que no empieces desde un lienzo en blanco.</li>\n</ul>\n<p>Si has usado Claude Design, su aspecto y comportamiento te resultarán familiares al instante: Open Design conserva deliberadamente la misma estética serena y luego añade capacidades por encima.</p>\n\n<h2>Antes de empezar</h2>\n<p>Tienes tres formas de instalar Open Design. Elige la que mejor te encaje:</p>\n<table>\n<thead><tr><th>Vía</th><th>Ideal para</th><th>Requisitos</th></tr></thead>\n<tbody>\n<tr><td><strong>Aplicación de escritorio</strong></td><td>La mayoría: cero configuración</td><td>Ninguno. Solo descárgala y ábrela.</td></tr>\n<tr><td><strong>Ejecutar desde el código fuente</strong></td><td>Desarrolladores que quieren leer o modificar el código</td><td>Node <code>~24</code>, pnpm <code>10.33.x</code></td></tr>\n<tr><td><strong>Instalar dentro de tu agente</strong></td><td>Quienes viven en la terminal</td><td>Una CLI de agente de programación ya instalada</td></tr>\n</tbody>\n</table>\n<p>El vídeo usa la vía de ejecutar desde el código fuente, pero hoy la <strong>aplicación de escritorio es la opción recomendada</strong>: no necesita Node, ni pnpm, ni clonar nada.</p>\n\n<h2>Paso 1: instala Open Design</h2>\n<h3>Opción A: aplicación de escritorio (recomendada, cero configuración)</h3>\n<p>Ve a <a href=\"https://open-design.ai/\">open-design.ai</a> y haz clic en <strong>Download desktop</strong>. Hay compilaciones disponibles para macOS (Apple Silicon e Intel), Windows (x64) y Linux (AppImage). Tras instalarla, la app detecta automáticamente todas las CLI de agentes de programación que ya tienes en tu <code>PATH</code> y carga por ti las skills y los sistemas de diseño integrados.</p>\n<h3>Opción B: ejecutar desde el código fuente</h3>\n<p>Si prefieres ejecutarlo desde el repositorio —como hace Dennis en el vídeo—, solo necesitas tres comandos:</p>\n<pre><code>git clone https://github.com/nexu-io/open-design.git\ncd open-design\ncorepack enable &amp;&amp; pnpm install\npnpm tools-dev run web</code></pre>\n<p>Luego abre la URL local que imprime (la interfaz web se ejecuta en <code>http://localhost:7456</code>). Necesitas Node <code>~24</code> y pnpm <code>10.33.x</code>; Corepack seleccionará por ti la versión de pnpm fijada.</p>\n<h3>Opción C: instalar dentro de tu agente de programación</h3>\n<p>Para usar Open Design sin abrir nunca la interfaz gráfica —invocándolo como una skill o un servidor MCP dentro de tu agente—, ejecuta:</p>\n<pre><code>curl -fsSL https://open-design.ai/install.sh | sh -s &lt;agent&gt;\n# &lt;agent&gt; = claude | codex | cursor | copilot | gemini | opencode | …</code></pre>\n<p>Después, dentro del agente, simplemente pídele: <code>Use open-design to generate a landing page with the Linear design system</code>.</p>\n\n<h2>Paso 2: primer arranque, conecta tu agente de programación</h2>\n<p>La primera vez que abres Open Design, este escanea tu máquina y te muestra todas las CLI locales que encontró: Claude Code, OpenCode, Copilot CLI y otras. Este es el paso de «trae tu propio agente».</p>\n<ul>\n<li><strong>Elige un agente y un modelo por defecto.</strong> Deja que la CLI instalada impulse la generación, o fuerza un modelo concreto (por ejemplo, Claude Opus) para este proyecto.</li>\n<li><strong>Añade proveedores de medios (opcional).</strong> ¿Quieres generar imágenes, vídeo o audio? Añade tus propias claves de API para proveedores como OpenAI (gpt-image), MiniMax, ElevenLabs, fal, Suno y más. Aquí es donde entra el trae tu propia clave.</li>\n<li><strong>Conecta servicios MCP (opcional).</strong> Integra conectores como Composio si quieres que el agente extraiga datos de otras fuentes.</li>\n<li><strong>Activa o desactiva skills y sistemas de diseño.</strong> Habilita solo las capacidades que necesitas para el tipo de trabajo que vas a hacer: prototipos, presentaciones, apps móviles, notas de reunión, etc.</li>\n</ul>\n<p>Puedes cambiar cualquiera de estas opciones más adelante, así que mantenlo sencillo en la primera pasada.</p>\n\n<h2>Paso 3: explora el espacio de trabajo</h2>\n<p>Open Design mantiene tu trabajo <strong>acotado por proyecto</strong>: cuando lo ejecutas sobre una carpeta, los diseños que creas viven dentro de ese directorio del proyecto. Cambia de carpeta y cambias de proyecto.</p>\n<p>Dentro de un proyecto puedes crear prototipos, artefactos en vivo, presentaciones y animaciones. Para los prototipos eliges entre dos niveles de fidelidad:</p>\n<ul>\n<li><strong>Wireframe</strong>: la estructura pura: cajas y formas para esbozar el layout rápidamente.</li>\n<li><strong>Alta fidelidad</strong>: un prototipo completo y con estilo de la página que estás construyendo.</li>\n</ul>\n<p>Una diferencia clave frente a Claude Design: <strong>no estás obligado a definir primero un sistema de diseño</strong>. Open Design viene con valores por defecto sensatos y una galería de puntos de partida, de modo que puedes empezar desde un sistema de diseño existente, o desde ninguno.</p>\n<p><img src=\"/tutorials/open-design-in-20-minutes/03-design-systems.webp\" alt=\"La biblioteca de sistemas de diseño de Open Design: puntos de partida de marcas reales que puedes previsualizar y reutilizar.\"></p>\n<p><em>La biblioteca de sistemas de diseño: puntos de partida de marcas reales (Agentic, Airbnb, Airtable y más) que puedes encajar en cualquier proyecto.</em></p>\n<p>El marketplace va mucho más allá de los sistemas de marca. La biblioteca de <strong>plantillas</strong> abarca prototipos, presentaciones y generación tanto de <strong>imagen como de vídeo</strong>: filtra por tipo y bifurca cualquiera como punto de partida.</p>\n<p><img src=\"/tutorials/open-design-in-20-minutes/04-templates.webp\" alt=\"La biblioteca de plantillas de Open Design, con puntos de partida de prototipo, imagen y vídeo.\"></p>\n<p><em>Plantillas: puntos de partida de prototipo, presentación, imagen y vídeo: filtra por tipo y bifurca para empezar.</em></p>\n<p>Puedes explorar la biblioteca completa de plugins en la web, en <a href=\"https://open-design.ai/plugins/\">open-design.ai/plugins</a>, antes de instalar nada.</p>\n\n<h2>Paso 4: crea tu primer prototipo</h2>\n<p>Ahora llega lo divertido. En el vídeo, Dennis importa un proyecto existente de Claude Design y le pide a Open Design que le construya una página nueva. Este es el mismo flujo:</p>\n<ol>\n<li><strong>Crea un prototipo nuevo.</strong> Ponle un nombre (Dennis llama al suyo «Expensely») y elige <strong>Alta fidelidad</strong>.</li>\n<li><strong>Importa tu sistema de diseño.</strong> Open Design puede importar un ZIP de Claude Design existente, así que tus tokens y componentes se trasladan. Los archivos de diseño importados aparecen en el espacio de trabajo junto a una vista previa en vivo.</li>\n<li><strong>Escribe el encargo.</strong> Dennis le pide <em>«create a new page projecting expenses for 12 months using the previous 3 months.»</em> Obtienes el familiar layout dividido: la conversación a la izquierda, la vista previa y los archivos de diseño a la derecha.</li>\n<li><strong>Responde las preguntas de aclaración.</strong> El agente plantea unas cuantas preguntas inteligentes de seguimiento —¿los mismos colores?, ¿qué fidelidad?, ¿una media simple de 3 meses?— y luego planifica una lista de tareas, lee el sistema de diseño y construye el artefacto (<code>projections-v2.html</code>).</li>\n<li><strong>Itera sobre el diseño.</strong> ¿No te convence el primer intento? Pide una dirección distinta. Dennis solicita «a different look and feel», elige una dirección <strong>editorial</strong> y obtiene un nuevo <code>projections-v3</code>: un diseño genuinamente diferente construido a partir de los mismos datos y el mismo sistema de diseño.</li>\n</ol>\n<p>El resultado es un prototipo real e interactivo: navega por los gráficos y las páginas, y luego expórtalo o entrégalo, todo construido a partir del sistema de diseño que importaste.</p>\n\n<h2>Consejos para sacarle más partido</h2>\n<ul>\n<li><strong>Empieza con alta fidelidad</strong> cuando quieras ver el resultado real; usa wireframe para esbozar la estructura rápidamente.</li>\n<li><strong>Tus diseños se quedan con la carpeta del proyecto</strong>: organiza tu trabajo ejecutando Open Design sobre el directorio adecuado.</li>\n<li><strong>Trae tus propias claves de medios</strong> solo para los proveedores que realmente uses; no necesitas todos.</li>\n<li><strong>No necesitas un sistema de diseño para empezar.</strong> Arranca desde uno integrado, importa un ZIP de Claude Design o deja que Open Design infiera los valores por defecto.</li>\n</ul>\n\n<h2>Preguntas frecuentes</h2>\n<p><strong>¿Open Design es gratis?</strong><br>Sí: es open source bajo la licencia Apache-2.0. Puedes ejecutarlo en local de forma gratuita; solo pagas por el uso de modelo/API del agente y los proveedores de medios que conectes.</p>\n<p><strong>¿Qué agentes de programación admite?</strong><br>Más de 21 agentes, incluidos Claude Code, Codex, Cursor, Gemini, GitHub Copilot y OpenCode. Open Design detecta las CLI que ya tienes instaladas en tu máquina.</p>\n<p><strong>¿Tengo que crear un sistema de diseño antes de poder diseñar?</strong><br>No. A diferencia de Claude Design, Open Design te da valores por defecto funcionales y una galería de puntos de partida. Puedes traer tu propio sistema de diseño cuando quieras uno.</p>\n<p><strong>¿En qué se diferencia de Claude Design?</strong><br>La misma sensación familiar, pero open source, local-first y con agentes intercambiables, además de capacidades extra como presentaciones, maquetas tipo revista, generación de imágenes y vídeo.</p>\n\n<hr>\n<p><em>Esta guía escrita está basada en el recorrido de primeras impresiones de CodingMenace. Mira el vídeo completo arriba y <a href=\"https://www.youtube.com/watch?v=QOqWZzecjuY\">suscríbete a CodingMenace</a> para más vídeos prácticos sobre herramientas de IA.</em></p>",
    },
    "pt-br": {
      title: "Open Design em 20 minutos — instalação completa + demonstração",
      summary: "Um tutorial completo para começar do zero — instale o Open Design, conecte seu coding agent, conheça o workspace e construa seu primeiro protótipo de alta fidelidade. Baseado no vídeo de primeiras impressões prático do CodingMenace.",
      bodyHtml: "<p>Este guia leva você pelos seus primeiros 20 minutos com o Open Design — de uma instalação limpa até seu primeiro protótipo gerado. Ele segue o caminho que o CodingMenace (Dennis) percorreu <a href=\"https://www.youtube.com/watch?v=QOqWZzecjuY\">no vídeo de primeiras impressões prático dele</a>, reescrito e atualizado para refletir a versão atual, para que você possa acompanhar passo a passo. Assista ao vídeo acima para ver o tutorial ao vivo, ou continue lendo para a versão escrita.</p>\n\n<p><img src=\"/tutorials/open-design-in-20-minutes/01-open-design-home.webp\" alt=\"A página inicial do Open Design — uma alternativa ao Claude Design que é open source, local e agent-native.\"></p>\n<p><em>O Open Design se posiciona como a alternativa open source ao Claude Design — desktop-first, agent-native, Apache-2.0.</em></p>\n\n<h2>O que é o Open Design?</h2>\n<p>O Open Design é uma plataforma de design open source e local-first — uma alternativa agent-native ao Claude Design e ao Figma. Em vez de prender você a um único provedor de modelos, ele roda <strong>em cima do coding agent que você já usa</strong>: Claude Code, Codex, Cursor, Gemini, Copilot, OpenCode e mais de uma dúzia de outros. É \"traga seu próprio agent\", não apenas traga sua própria chave.</p>\n<p>Algumas coisas que fazem dele algo que vale a pena conferir:</p>\n<ul>\n<li><strong>Open source, Apache-2.0</strong> — clone, faça self-host, leia cada linha.</li>\n<li><strong>Roda localmente</strong> — seus projetos ficam nas suas próprias pastas, na sua máquina, e não na nuvem de outra pessoa.</li>\n<li><strong>Agents plugáveis</strong> — mais de 21 coding agents são suportados; você escolhe qual CLI vai conduzir a geração.</li>\n<li><strong>Muito além de protótipos</strong> — protótipos, artefatos vivos, apresentações de slides, layouts estilo revista, geração de imagens e até vídeo, tudo a partir de um único workspace.</li>\n<li><strong>Uma ampla biblioteca de design systems e skills</strong> já embutidos, para que você não comece de uma tela em branco.</li>\n</ul>\n<p>Se você já usou o Claude Design, a aparência e a experiência serão imediatamente familiares — o Open Design mantém deliberadamente a mesma estética tranquila e, em cima disso, adiciona recursos.</p>\n\n<h2>Antes de começar</h2>\n<p>Você tem três formas de instalar o Open Design. Escolha a que melhor combina com você:</p>\n<table>\n<thead><tr><th>Caminho</th><th>Ideal para</th><th>Requisitos</th></tr></thead>\n<tbody>\n<tr><td><strong>App desktop</strong></td><td>A maioria das pessoas — zero configuração</td><td>Nenhum. Basta baixar e abrir.</td></tr>\n<tr><td><strong>Rodar a partir do código-fonte</strong></td><td>Desenvolvedores que querem ler ou modificar o código</td><td>Node <code>~24</code>, pnpm <code>10.33.x</code></td></tr>\n<tr><td><strong>Instalar dentro do seu agent</strong></td><td>Quem vive no terminal</td><td>Uma CLI de coding agent já existente</td></tr>\n</tbody>\n</table>\n<p>O vídeo usa o caminho de rodar a partir do código-fonte, mas o <strong>app desktop é a rota recomendada</strong> hoje — ele não precisa de Node, nem de pnpm, nem de clonar o repositório.</p>\n\n<h2>Passo 1 — Instale o Open Design</h2>\n<h3>Opção A — App desktop (recomendado, zero configuração)</h3>\n<p>Acesse <a href=\"https://open-design.ai/\">open-design.ai</a> e clique em <strong>Download desktop</strong>. Há builds disponíveis para macOS (Apple Silicon e Intel), Windows (x64) e Linux (AppImage). Após instalar, o app detecta automaticamente todas as CLIs de coding agent já presentes no seu <code>PATH</code> e carrega para você as skills e os design systems embutidos.</p>\n<h3>Opção B — Rodar a partir do código-fonte</h3>\n<p>Se você preferir rodar a partir do repositório — como o Dennis faz no vídeo —, basta executar três comandos:</p>\n<pre><code>git clone https://github.com/nexu-io/open-design.git\ncd open-design\ncorepack enable &amp;&amp; pnpm install\npnpm tools-dev run web</code></pre>\n<p>Depois, abra a URL local que ele imprime (a interface web roda em <code>http://localhost:7456</code>). Você precisa de Node <code>~24</code> e pnpm <code>10.33.x</code>; o Corepack vai selecionar para você a versão fixada do pnpm.</p>\n<h3>Opção C — Instale dentro do seu coding agent</h3>\n<p>Para usar o Open Design sem nunca abrir a interface gráfica — chamando-o como uma skill ou um servidor MCP dentro do seu agent —, execute:</p>\n<pre><code>curl -fsSL https://open-design.ai/install.sh | sh -s &lt;agent&gt;\n# &lt;agent&gt; = claude | codex | cursor | copilot | gemini | opencode | …</code></pre>\n<p>Depois, dentro do agent, basta pedir: <code>Use open-design to generate a landing page with the Linear design system</code>.</p>\n\n<h2>Passo 2 — Primeira execução: conecte seu coding agent</h2>\n<p>Na primeira vez que você inicia o Open Design, ele escaneia sua máquina e mostra todas as CLIs locais que encontrou — Claude Code, OpenCode, Copilot CLI e outras. Esta é a etapa do \"traga seu próprio agent\".</p>\n<ul>\n<li><strong>Escolha um agent e um modelo padrão.</strong> Deixe a CLI instalada conduzir a geração, ou force um modelo específico (por exemplo, Claude Opus) para este projeto.</li>\n<li><strong>Adicione provedores de mídia (opcional).</strong> Quer gerar imagens, vídeo ou áudio? Adicione suas próprias chaves de API de provedores como OpenAI (gpt-image), MiniMax, ElevenLabs, fal, Suno e mais. É aqui que entra o traga sua própria chave.</li>\n<li><strong>Conecte serviços MCP (opcional).</strong> Integre conectores como o Composio se quiser que o agent puxe dados de outras fontes.</li>\n<li><strong>Ative skills e design systems.</strong> Habilite apenas os recursos de que você precisa para o tipo de trabalho que está fazendo — protótipos, apresentações de slides, apps mobile, notas de reunião e assim por diante.</li>\n</ul>\n<p>Você pode mudar qualquer uma dessas configurações depois, então mantenha tudo simples na primeira passada.</p>\n\n<h2>Passo 3 — Explore o workspace</h2>\n<p>O Open Design mantém seu trabalho <strong>com escopo por projeto</strong>: quando você o executa em uma pasta, os designs que você cria ficam dentro daquele diretório do projeto. Troque de pasta e você troca de projeto.</p>\n<p>Dentro de um projeto, você pode criar protótipos, artefatos vivos, apresentações de slides e animações. Para protótipos, você escolhe entre duas fidelidades:</p>\n<ul>\n<li><strong>Wireframe</strong> — a estrutura crua: caixas e formas para esboçar o layout rapidamente.</li>\n<li><strong>Alta fidelidade</strong> — um protótipo completo e estilizado da página que você está construindo.</li>\n</ul>\n<p>Uma diferença importante em relação ao Claude Design: você <strong>não é obrigado a definir um design system antes</strong>. O Open Design vem com padrões sensatos e uma galeria de pontos de partida, então você pode começar a partir de um design system existente — ou de nenhum.</p>\n<p><img src=\"/tutorials/open-design-in-20-minutes/03-design-systems.webp\" alt=\"A biblioteca de design systems do Open Design — pontos de partida de marcas reais que você pode pré-visualizar e reutilizar.\"></p>\n<p><em>A biblioteca de design systems: pontos de partida de marcas do mundo real (Agentic, Airbnb, Airtable e mais) que você pode encaixar em qualquer projeto.</em></p>\n<p>O marketplace vai bem além dos sistemas de marca. A biblioteca de <strong>templates</strong> cobre protótipos, slides e geração de <strong>imagens e vídeo</strong> — filtre por tipo e faça fork de qualquer um como ponto de partida.</p>\n<p><img src=\"/tutorials/open-design-in-20-minutes/04-templates.webp\" alt=\"A biblioteca de templates do Open Design, com pontos de partida de protótipo, imagem e vídeo.\"></p>\n<p><em>Templates: pontos de partida de protótipo, slide, imagem e vídeo — filtre por tipo e faça fork para começar.</em></p>\n<p>Você pode navegar pela biblioteca completa de plugins na web em <a href=\"https://open-design.ai/plugins/\">open-design.ai/plugins</a> antes de instalar qualquer coisa.</p>\n\n<h2>Passo 4 — Construa seu primeiro protótipo</h2>\n<p>Agora a parte divertida. No vídeo, o Dennis importa um projeto existente do Claude Design e pede ao Open Design para construir uma nova página para ele. Aqui está o mesmo fluxo:</p>\n<ol>\n<li><strong>Crie um novo protótipo.</strong> Dê um nome a ele (o Dennis chama o dele de \"Expensely\") e escolha <strong>Alta fidelidade</strong>.</li>\n<li><strong>Importe seu design system.</strong> O Open Design pode importar um ZIP existente do Claude Design, então seus tokens e componentes são preservados. Os arquivos de design importados aparecem no workspace ao lado de um preview ao vivo.</li>\n<li><strong>Escreva o briefing.</strong> O Dennis pede a ele para <em>\"create a new page projecting expenses for 12 months using the previous 3 months.\"</em> Você obtém o layout dividido familiar: a conversa à esquerda, o preview e os arquivos de design à direita.</li>\n<li><strong>Responda às perguntas de esclarecimento.</strong> O agent faz alguns follow-ups inteligentes — mesmas cores? qual fidelidade? média simples de 3 meses? — e então planeja uma lista de tarefas, lê o design system e constrói o artefato (<code>projections-v2.html</code>).</li>\n<li><strong>Itere sobre o design.</strong> Não gostou da primeira versão? Peça uma direção diferente. O Dennis pede \"a different look and feel\", escolhe uma direção <strong>editorial</strong> e obtém um novo <code>projections-v3</code> — um design genuinamente diferente, construído a partir dos mesmos dados e do mesmo design system.</li>\n</ol>\n<p>O resultado é um protótipo real e interativo: navegue pelos gráficos e páginas, depois exporte ou faça o handoff — tudo construído a partir do design system que você importou.</p>\n\n<h2>Dicas para tirar mais proveito</h2>\n<ul>\n<li><strong>Comece pela alta fidelidade</strong> quando quiser ver a coisa real; use o wireframe para esboçar a estrutura rapidamente.</li>\n<li><strong>Seus designs ficam junto com a pasta do projeto</strong> — organize o trabalho executando o Open Design no diretório certo.</li>\n<li><strong>Traga suas próprias chaves de mídia</strong> apenas para os provedores que você realmente usa; você não precisa de todas elas.</li>\n<li><strong>Você não precisa de um design system para começar.</strong> Parta de um embutido, importe um ZIP do Claude Design ou deixe o Open Design inferir os padrões.</li>\n</ul>\n\n<h2>Perguntas frequentes</h2>\n<p><strong>O Open Design é gratuito?</strong><br>Sim — ele é open source sob a licença Apache-2.0. Você pode rodá-lo localmente de graça; você só paga pelo uso de modelo/API de qualquer agent e provedores de mídia que conectar.</p>\n<p><strong>Quais coding agents ele suporta?</strong><br>Mais de 21 agents, incluindo Claude Code, Codex, Cursor, Gemini, GitHub Copilot e OpenCode. O Open Design detecta as CLIs já instaladas na sua máquina.</p>\n<p><strong>Preciso criar um design system antes de poder projetar?</strong><br>Não. Diferentemente do Claude Design, o Open Design oferece padrões funcionais e uma galeria de pontos de partida. Você pode trazer seu próprio design system quando quiser um.</p>\n<p><strong>Como ele se diferencia do Claude Design?</strong><br>A mesma experiência familiar, mas open source, local-first e com agents plugáveis — além de recursos extras como apresentações de slides, layouts estilo revista, geração de imagens e vídeo.</p>\n\n<hr>\n<p><em>Este guia escrito é baseado no tutorial de primeiras impressões do CodingMenace. Assista ao vídeo completo acima e <a href=\"https://www.youtube.com/watch?v=QOqWZzecjuY\">inscreva-se no canal do CodingMenace</a> para mais vídeos práticos sobre ferramentas de IA.</em></p>",
    },
    "it": {
      title: "Open Design in 20 minuti — Setup completo + Demo",
      summary: "Una guida introduttiva completa: installa Open Design, collega il tuo coding agent, esplora il workspace e crea il tuo primo prototipo ad alta fedeltà. Basata sul video di prime impressioni pratiche di CodingMenace.",
      bodyHtml: "<p>Questa guida ti accompagna nei tuoi primi 20 minuti con Open Design — da un'installazione pulita fino al tuo primo prototipo generato. Segue il percorso intrapreso da CodingMenace (Dennis) nel <a href=\"https://www.youtube.com/watch?v=QOqWZzecjuY\">suo video di prime impressioni pratiche</a>, riscritto e aggiornato per allinearsi alla release attuale, così puoi seguirlo passo dopo passo. Guarda il video qui sopra per la dimostrazione dal vivo, oppure continua a leggere per la versione scritta.</p>\n\n<p><img src=\"/tutorials/open-design-in-20-minutes/01-open-design-home.webp\" alt=\"La home page di Open Design — un'alternativa a Claude Design open source, locale e agent-native.\"></p>\n<p><em>Open Design si presenta come l'alternativa open source a Claude Design — desktop-first, agent-native, Apache-2.0.</em></p>\n\n<h2>Cos'è Open Design?</h2>\n<p>Open Design è una piattaforma di design open source e local-first — un'alternativa agent-native a Claude Design e Figma. Invece di vincolarti a un unico fornitore di modelli, gira <strong>sopra il coding agent che già usi</strong>: Claude Code, Codex, Cursor, Gemini, Copilot, OpenCode e una dozzina di altri. È \"bring your own agent\", non solo bring your own key.</p>\n<p>Alcune cose che lo rendono degno di attenzione:</p>\n<ul>\n<li><strong>Open source, Apache-2.0</strong> — clonalo, fai self-hosting, leggi ogni singola riga.</li>\n<li><strong>Gira in locale</strong> — i tuoi progetti vivono nelle tue cartelle, sulla tua macchina, non nel cloud di qualcun altro.</li>\n<li><strong>Agente intercambiabile</strong> — sono supportati oltre 21 coding agent; scegli tu quale CLI guida la generazione.</li>\n<li><strong>Molto più dei prototipi</strong> — prototipi, artifact live, slide deck, layout in stile rivista, generazione di immagini e persino video, tutto da un unico workspace.</li>\n<li><strong>Un'ampia libreria di design system e skill</strong> integrati, così non parti da una tela bianca.</li>\n</ul>\n<p>Se hai già usato Claude Design, l'aspetto e l'esperienza ti risulteranno immediatamente familiari — Open Design mantiene volutamente la stessa estetica pacata, aggiungendoci poi nuove capacità.</p>\n\n<h2>Prima di iniziare</h2>\n<p>Hai tre modi per installare Open Design. Scegli quello più adatto a te:</p>\n<table>\n<thead><tr><th>Percorso</th><th>Ideale per</th><th>Requisiti</th></tr></thead>\n<tbody>\n<tr><td><strong>App desktop</strong></td><td>La maggior parte delle persone — zero configurazione</td><td>Nessuno. Basta scaricare e aprire.</td></tr>\n<tr><td><strong>Esecuzione da sorgente</strong></td><td>Sviluppatori che vogliono leggere o modificare il codice</td><td>Node <code>~24</code>, pnpm <code>10.33.x</code></td></tr>\n<tr><td><strong>Installazione nel tuo agent</strong></td><td>Chi vive nel terminale</td><td>Una CLI di coding agent già installata</td></tr>\n</tbody>\n</table>\n<p>Il video usa il percorso di esecuzione da sorgente, ma oggi <strong>l'app desktop è la strada consigliata</strong> — non richiede né Node, né pnpm, né alcun clone.</p>\n\n<h2>Passo 1 — Installa Open Design</h2>\n<h3>Opzione A — App desktop (consigliata, zero configurazione)</h3>\n<p>Vai su <a href=\"https://open-design.ai/\">open-design.ai</a> e clicca su <strong>Download desktop</strong>. Sono disponibili build per macOS (Apple Silicon e Intel), Windows (x64) e Linux (AppImage). Dopo l'installazione, l'app rileva automaticamente ogni CLI di coding agent già presente nel tuo <code>PATH</code> e carica per te le skill e i design system integrati.</p>\n<h3>Opzione B — Esecuzione da sorgente</h3>\n<p>Se invece preferisci eseguirlo dal repository — come fa Dennis nel video — ti bastano tre comandi:</p>\n<pre><code>git clone https://github.com/nexu-io/open-design.git\ncd open-design\ncorepack enable &amp;&amp; pnpm install\npnpm tools-dev run web</code></pre>\n<p>Poi apri l'URL locale che viene stampato (la UI web gira su <code>http://localhost:7456</code>). Ti servono Node <code>~24</code> e pnpm <code>10.33.x</code>; Corepack selezionerà per te la versione di pnpm fissata.</p>\n<h3>Opzione C — Installazione nel tuo coding agent</h3>\n<p>Per usare Open Design senza mai aprire la GUI — richiamandolo come skill o server MCP all'interno del tuo agent — esegui:</p>\n<pre><code>curl -fsSL https://open-design.ai/install.sh | sh -s &lt;agent&gt;\n# &lt;agent&gt; = claude | codex | cursor | copilot | gemini | opencode | …</code></pre>\n<p>Poi, all'interno dell'agent, basta chiedere: <code>Use open-design to generate a landing page with the Linear design system</code>.</p>\n\n<h2>Passo 2 — Primo avvio: collega il tuo coding agent</h2>\n<p>La prima volta che avvii Open Design, esegue una scansione della tua macchina e ti mostra ogni CLI locale trovata — Claude Code, OpenCode, Copilot CLI e altre. Questo è il passaggio \"bring your own agent\".</p>\n<ul>\n<li><strong>Scegli un agent e un modello predefiniti.</strong> Lascia che sia la CLI installata a guidare la generazione, oppure imponi un modello specifico (ad esempio Claude Opus) per questo progetto.</li>\n<li><strong>Aggiungi provider multimediali (facoltativo).</strong> Vuoi generare immagini, video o audio? Aggiungi le tue API key per provider come OpenAI (gpt-image), MiniMax, ElevenLabs, fal, Suno e altri. È qui che entra in gioco il bring-your-own-key.</li>\n<li><strong>Collega servizi MCP (facoltativo).</strong> Integra connettori come Composio se vuoi che l'agent recuperi dati da altre fonti.</li>\n<li><strong>Attiva skill e design system.</strong> Abilita solo le capacità che ti servono per il tipo di lavoro che stai facendo — prototipi, slide deck, app mobile, note di riunione e così via.</li>\n</ul>\n<p>Potrai modificare tutto questo in seguito, quindi al primo giro mantieni le cose semplici.</p>\n\n<h2>Passo 3 — Esplora il workspace</h2>\n<p>Open Design tiene il tuo lavoro <strong>circoscritto al progetto</strong>: quando lo esegui su una cartella, i design che crei vivono dentro quella directory di progetto. Cambia cartella e cambi progetto.</p>\n<p>All'interno di un progetto puoi creare prototipi, artifact live, slide deck e animazioni. Per i prototipi scegli tra due livelli di fedeltà:</p>\n<ul>\n<li><strong>Wireframe</strong> — la struttura essenziale: riquadri e forme per abbozzare velocemente il layout.</li>\n<li><strong>Alta fedeltà</strong> — un prototipo completo e rifinito della pagina che stai costruendo.</li>\n</ul>\n<p>Una differenza chiave rispetto a Claude Design: <strong>non sei costretto a definire prima un design system</strong>. Open Design fornisce impostazioni predefinite sensate e una galleria di punti di partenza, così puoi cominciare da un design system esistente — o da nessuno.</p>\n<p><img src=\"/tutorials/open-design-in-20-minutes/03-design-systems.webp\" alt=\"La libreria dei design system di Open Design — veri punti di partenza basati su brand reali da visualizzare e riutilizzare.\"></p>\n<p><em>La libreria dei design system: punti di partenza basati su brand reali (Agentic, Airbnb, Airtable e altri) che puoi inserire in qualsiasi progetto.</em></p>\n<p>Il marketplace va ben oltre i sistemi di brand. La libreria dei <strong>template</strong> copre prototipi, slide e generazione sia di <strong>immagini che di video</strong> — filtra per tipo e fai il fork di uno qualsiasi come punto di partenza.</p>\n<p><img src=\"/tutorials/open-design-in-20-minutes/04-templates.webp\" alt=\"La libreria dei template di Open Design, con punti di partenza per prototipi, immagini e video.\"></p>\n<p><em>Template: punti di partenza per prototipi, slide, immagini e video — filtra per tipo e fai il fork per iniziare.</em></p>\n<p>Puoi sfogliare l'intera libreria di plugin sul web su <a href=\"https://open-design.ai/plugins/\">open-design.ai/plugins</a> prima di installare qualsiasi cosa.</p>\n\n<h2>Passo 4 — Crea il tuo primo prototipo</h2>\n<p>Ora la parte divertente. Nel video, Dennis importa un progetto Claude Design esistente e chiede a Open Design di costruirgli una nuova pagina. Ecco lo stesso flusso:</p>\n<ol>\n<li><strong>Crea un nuovo prototipo.</strong> Dagli un nome (Dennis chiama il suo \"Expensely\") e scegli <strong>Alta fedeltà</strong>.</li>\n<li><strong>Importa il tuo design system.</strong> Open Design può importare uno ZIP di Claude Design esistente, così i tuoi token e componenti vengono trasferiti. I file di design importati compaiono nel workspace insieme a un'anteprima live.</li>\n<li><strong>Scrivi il brief.</strong> Dennis lo istruisce con <em>\"create a new page projecting expenses for 12 months using the previous 3 months.\"</em> Ottieni il familiare layout diviso: la conversazione a sinistra, l'anteprima e i file di design a destra.</li>\n<li><strong>Rispondi alle domande di chiarimento.</strong> L'agent pone qualche follow-up intelligente — stessi colori? quale fedeltà? semplice media a 3 mesi? — poi pianifica una to-do list, legge il design system e costruisce l'artifact (<code>projections-v2.html</code>).</li>\n<li><strong>Itera sul design.</strong> Non sei soddisfatto del primo risultato? Chiedi una direzione diversa. Dennis chiede \"a different look and feel\", sceglie una direzione <strong>editoriale</strong> e ottiene un nuovo <code>projections-v3</code> — un design davvero diverso costruito dagli stessi dati e dallo stesso design system.</li>\n</ol>\n<p>Il risultato è un prototipo reale e interattivo: clicca tra i grafici e le pagine, poi esporta o passa la consegna — tutto costruito a partire dal design system che hai importato.</p>\n\n<h2>Consigli per sfruttarlo al meglio</h2>\n<ul>\n<li><strong>Parti dall'alta fedeltà</strong> quando vuoi vedere il risultato vero e proprio; usa il wireframe per abbozzare velocemente la struttura.</li>\n<li><strong>I tuoi design restano con la cartella del progetto</strong> — organizza il lavoro eseguendo Open Design sulla directory giusta.</li>\n<li><strong>Porta le tue media key</strong> solo per i provider che usi davvero; non ti servono tutti.</li>\n<li><strong>Non ti serve un design system per iniziare.</strong> Parti da uno integrato, importa uno ZIP di Claude Design oppure lascia che Open Design deduca le impostazioni predefinite.</li>\n</ul>\n\n<h2>FAQ</h2>\n<p><strong>Open Design è gratuito?</strong><br>Sì — è open source con licenza Apache-2.0. Puoi eseguirlo in locale gratuitamente; paghi solo per l'uso del modello/API dell'agent e dei provider multimediali che colleghi.</p>\n<p><strong>Quali coding agent supporta?</strong><br>Oltre 21 agent, tra cui Claude Code, Codex, Cursor, Gemini, GitHub Copilot e OpenCode. Open Design rileva le CLI già installate sulla tua macchina.</p>\n<p><strong>Devo creare un design system prima di poter progettare?</strong><br>No. A differenza di Claude Design, Open Design ti offre impostazioni predefinite funzionanti e una galleria di punti di partenza. Puoi portare il tuo design system quando ne vuoi uno.</p>\n<p><strong>In cosa si differenzia da Claude Design?</strong><br>Stessa esperienza familiare, ma open source, local-first e con agente intercambiabile — più capacità extra come slide deck, layout in stile rivista, generazione di immagini e video.</p>\n\n<hr>\n<p><em>Questa guida scritta è basata sulla panoramica di prime impressioni di CodingMenace. Guarda il video completo qui sopra e <a href=\"https://www.youtube.com/watch?v=QOqWZzecjuY\">iscriviti a CodingMenace</a> per altri video pratici sugli strumenti AI.</em></p>",
    },
    "tr": {
      title: "20 Dakikada Open Design — Eksiksiz Kurulum + Demo",
      summary: "Baştan sona bir başlangıç rehberi — Open Design'ı kurun, kodlama agent'ınızı bağlayın, çalışma alanında gezinin ve ilk yüksek doğruluklu prototipinizi oluşturun. CodingMenace'in uygulamalı ilk-izlenim videosundan uyarlanmıştır.",
      bodyHtml: "<p>Bu rehber, Open Design ile geçireceğiniz ilk 20 dakikada size eşlik ediyor — temiz bir kurulumdan ilk ürettiğiniz prototipe kadar. CodingMenace'in (Dennis) <a href=\"https://www.youtube.com/watch?v=QOqWZzecjuY\">uygulamalı ilk-izlenim videosunda</a> izlediği yolu takip ediyor; adım adım birlikte ilerleyebilmeniz için mevcut sürüme uyacak şekilde yeniden yazıldı ve güncellendi. Canlı anlatım için yukarıdaki videoyu izleyin ya da yazılı sürüm için okumaya devam edin.</p>\n\n<p><img src=\"/tutorials/open-design-in-20-minutes/01-open-design-home.webp\" alt=\"Open Design ana sayfası — açık kaynaklı, yerel, agent-native bir Claude Design alternatifi.\"></p>\n<p><em>Open Design kendisini açık kaynaklı Claude Design alternatifi olarak konumlandırıyor — önce masaüstü, agent-native, Apache-2.0.</em></p>\n\n<h2>Open Design nedir?</h2>\n<p>Open Design, açık kaynaklı, önce-yerel bir tasarım platformudur — Claude Design ve Figma'ya agent-native bir alternatif. Sizi tek bir model sağlayıcısına kilitlemek yerine, <strong>zaten kullandığınız kodlama agent'ının üzerinde</strong> çalışır: Claude Code, Codex, Cursor, Gemini, Copilot, OpenCode ve daha bir düzine başkası. Bu yalnızca kendi anahtarını getir değil, kendi agent'ını getir mantığıdır.</p>\n<p>Göz atmaya değer kılan birkaç şey:</p>\n<ul>\n<li><strong>Açık kaynak, Apache-2.0</strong> — klonlayın, kendi sunucunuzda barındırın, her satırı okuyun.</li>\n<li><strong>Yerel çalışır</strong> — projeleriniz başkasının bulutunda değil, kendi makinenizdeki kendi klasörlerinizde yaşar.</li>\n<li><strong>Agent takılabilir</strong> — 21+ kodlama agent'ı destekleniyor; üretimi hangi CLI'nin yöneteceğini siz seçersiniz.</li>\n<li><strong>Prototiplerden fazlası</strong> — prototipler, canlı çıktılar, sunum desteleri, dergi düzenleri, görsel üretimi ve hatta video, hepsi tek bir çalışma alanından.</li>\n<li><strong>Zengin bir tasarım sistemi ve beceri kütüphanesi</strong> yerleşik olarak gelir, böylece boş bir tuvalden başlamazsınız.</li>\n</ul>\n<p>Claude Design kullandıysanız, görünüm ve his anında tanıdık gelecek — Open Design bilinçli olarak aynı sakin estetiği korur, sonra üzerine yetenekler ekler.</p>\n\n<h2>Başlamadan önce</h2>\n<p>Open Design'ı kurmanın üç yolu var. Size uygun olanı seçin:</p>\n<table>\n<thead><tr><th>Yöntem</th><th>Kimin için en iyi</th><th>Gereksinimler</th></tr></thead>\n<tbody>\n<tr><td><strong>Masaüstü uygulaması</strong></td><td>Çoğu kişi — sıfır yapılandırma</td><td>Yok. Sadece indirin ve açın.</td></tr>\n<tr><td><strong>Kaynaktan çalıştırma</strong></td><td>Kodu okumak ya da değiştirmek isteyen geliştiriciler</td><td>Node <code>~24</code>, pnpm <code>10.33.x</code></td></tr>\n<tr><td><strong>Agent'ınıza kurma</strong></td><td>Terminalde yaşayanlar</td><td>Mevcut bir kodlama-agent'ı CLI'si</td></tr>\n</tbody>\n</table>\n<p>Video kaynaktan-çalıştırma yöntemini kullanıyor, ancak bugün <strong>önerilen yol masaüstü uygulamasıdır</strong> — Node, pnpm ya da klonlama gerektirmez.</p>\n\n<h2>Adım 1 — Open Design'ı kurun</h2>\n<h3>Seçenek A — Masaüstü uygulaması (önerilir, sıfır yapılandırma)</h3>\n<p><a href=\"https://open-design.ai/\">open-design.ai</a> adresine gidin ve <strong>Download desktop</strong>'a tıklayın. Yapılar macOS (Apple Silicon ve Intel), Windows (x64) ve Linux (AppImage) için mevcut. Kurulumdan sonra uygulama, <code>PATH</code>'inizde zaten bulunan her kodlama-agent'ı CLI'sini otomatik algılar ve yerleşik becerileri ile tasarım sistemlerini sizin için yükler.</p>\n<h3>Seçenek B — Kaynaktan çalıştırma</h3>\n<p>Bunun yerine — Dennis'in videoda yaptığı gibi — depodan çalıştırmayı tercih ederseniz, yalnızca üç komuta ihtiyacınız var:</p>\n<pre><code>git clone https://github.com/nexu-io/open-design.git\ncd open-design\ncorepack enable &amp;&amp; pnpm install\npnpm tools-dev run web</code></pre>\n<p>Ardından yazdırdığı yerel URL'yi açın (web arayüzü <code>http://localhost:7456</code> adresinde çalışır). Node <code>~24</code> ve pnpm <code>10.33.x</code> gerekir; Corepack sabitlenmiş pnpm sürümünü sizin için seçer.</p>\n<h3>Seçenek C — Kodlama agent'ınıza kurma</h3>\n<p>Open Design'ı GUI'yi hiç açmadan kullanmak için — agent'ınızın içinde bir beceri ya da MCP sunucusu olarak çağırarak — şunu çalıştırın:</p>\n<pre><code>curl -fsSL https://open-design.ai/install.sh | sh -s &lt;agent&gt;\n# &lt;agent&gt; = claude | codex | cursor | copilot | gemini | opencode | …</code></pre>\n<p>Ardından agent'ın içinde sadece şunu isteyin: <code>Use open-design to generate a landing page with the Linear design system</code>.</p>\n\n<h2>Adım 2 — İlk çalıştırma: kodlama agent'ınızı bağlayın</h2>\n<p>Open Design'ı ilk kez başlattığınızda, makinenizi tarar ve bulduğu her yerel CLI'yi gösterir — Claude Code, OpenCode, Copilot CLI ve diğerleri. Bu, \"kendi agent'ını getir\" adımıdır.</p>\n<ul>\n<li><strong>Varsayılan bir agent ve model seçin.</strong> Üretimi kurulu CLI'nin yönetmesine izin verin ya da bu proje için belirli bir modeli (örneğin Claude Opus) zorunlu kılın.</li>\n<li><strong>Medya sağlayıcıları ekleyin (isteğe bağlı).</strong> Görsel, video ya da ses üretmek mi istiyorsunuz? OpenAI (gpt-image), MiniMax, ElevenLabs, fal, Suno ve daha fazlası gibi sağlayıcılar için kendi API anahtarlarınızı ekleyin. Kendi anahtarını getir işte burada devreye giriyor.</li>\n<li><strong>MCP servislerini bağlayın (isteğe bağlı).</strong> Agent'ın başka kaynaklardan veri çekmesini istiyorsanız Composio gibi konnektörleri bağlayın.</li>\n<li><strong>Becerileri ve tasarım sistemlerini açıp kapatın.</strong> Yalnızca yaptığınız iş türü için ihtiyacınız olan yetenekleri etkinleştirin — prototipler, sunum desteleri, mobil uygulamalar, toplantı notları vb.</li>\n</ul>\n<p>Bunların hepsini daha sonra değiştirebilirsiniz, bu yüzden ilk seferde basit tutun.</p>\n\n<h2>Adım 3 — Çalışma alanını keşfedin</h2>\n<p>Open Design çalışmanızı <strong>proje kapsamlı</strong> tutar: bir klasör üzerinde çalıştırdığınızda, oluşturduğunuz tasarımlar o proje dizininin içinde yaşar. Klasör değiştirin, proje değişir.</p>\n<p>Bir proje içinde prototipler, canlı çıktılar, sunum desteleri ve animasyonlar oluşturabilirsiniz. Prototipler için iki doğruluk düzeyi arasında seçim yaparsınız:</p>\n<ul>\n<li><strong>Tel çerçeve (wireframe)</strong> — yalın yapı: düzeni hızlıca taslaklamak için kutular ve şekiller.</li>\n<li><strong>Yüksek doğruluk</strong> — oluşturduğunuz sayfanın tam, stillendirilmiş bir prototipi.</li>\n</ul>\n<p>Claude Design'dan önemli bir fark: <strong>önce bir tasarım sistemi tanımlamak zorunda değilsiniz</strong>. Open Design makul varsayılanlar ve bir başlangıç noktaları galerisiyle gelir, böylece mevcut bir tasarım sisteminden — ya da hiçbirinden — başlayabilirsiniz.</p>\n<p><img src=\"/tutorials/open-design-in-20-minutes/03-design-systems.webp\" alt=\"Open Design tasarım-sistemleri kütüphanesi — önizleyip yeniden kullanabileceğiniz gerçek marka başlangıç noktaları.\"></p>\n<p><em>Tasarım-sistemleri kütüphanesi: herhangi bir projeye yerleştirebileceğiniz gerçek dünya marka başlangıç noktaları (Agentic, Airbnb, Airtable ve daha fazlası).</em></p>\n<p>Pazar yeri marka sistemlerinin çok ötesine geçiyor. <strong>Şablonlar</strong> kütüphanesi prototipleri, sunumları ve hem <strong>görsel hem de video</strong> üretimini kapsar — türe göre filtreleyin ve herhangi birini başlangıç noktanız olarak çatallayın (fork).</p>\n<p><img src=\"/tutorials/open-design-in-20-minutes/04-templates.webp\" alt=\"Open Design şablonlar kütüphanesi; prototip, görsel ve video başlangıç noktalarıyla.\"></p>\n<p><em>Şablonlar: prototip, sunum, görsel ve video başlangıç noktaları — türe göre filtreleyin ve başlamak için çatallayın.</em></p>\n<p>Herhangi bir şey kurmadan önce tam eklenti kütüphanesine web üzerinden <a href=\"https://open-design.ai/plugins/\">open-design.ai/plugins</a> adresinden göz atabilirsiniz.</p>\n\n<h2>Adım 4 — İlk prototipinizi oluşturun</h2>\n<p>Şimdi eğlenceli kısım. Videoda Dennis mevcut bir Claude Design projesini içe aktarıyor ve Open Design'dan onun için yeni bir sayfa oluşturmasını istiyor. İşte aynı akış:</p>\n<ol>\n<li><strong>Yeni bir prototip oluşturun.</strong> Ona bir ad verin (Dennis kendisininkine \"Expensely\" diyor) ve <strong>Yüksek doğruluk</strong>'u seçin.</li>\n<li><strong>Tasarım sisteminizi içe aktarın.</strong> Open Design mevcut bir Claude Design ZIP'ini içe aktarabilir, böylece token'larınız ve bileşenleriniz aktarılır. İçe aktarılan tasarım dosyaları, canlı bir önizlemenin yanında çalışma alanında görünür.</li>\n<li><strong>Brief'i yazın.</strong> Dennis ona şunu istiyor: <em>\"create a new page projecting expenses for 12 months using the previous 3 months.\"</em> Tanıdık bölünmüş düzeni elde edersiniz: solda konuşma, sağda önizleme ve tasarım dosyaları.</li>\n<li><strong>Netleştirici soruları yanıtlayın.</strong> Agent birkaç akıllı takip sorusu sorar — aynı renkler mi? hangi doğruluk düzeyi? basit 3 aylık ortalama mı? — ardından bir yapılacaklar listesi planlar, tasarım sistemini okur ve çıktıyı oluşturur (<code>projections-v2.html</code>).</li>\n<li><strong>Tasarım üzerinde yineleme yapın.</strong> İlk denemeden memnun değil misiniz? Farklı bir yön isteyin. Dennis \"farklı bir görünüm ve his\" istiyor, <strong>editöryel</strong> bir yön seçiyor ve taptaze bir <code>projections-v3</code> elde ediyor — aynı veri ve tasarım sisteminden oluşturulmuş gerçekten farklı bir tasarım.</li>\n</ol>\n<p>Sonuç gerçek, etkileşimli bir prototip: grafikler ve sayfalar arasında tıklayarak gezin, ardından dışa aktarın ya da devredin — hepsi içe aktardığınız tasarım sisteminden oluşturuldu.</p>\n\n<h2>Daha fazlasını elde etmek için ipuçları</h2>\n<ul>\n<li>Gerçek halini görmek istediğinizde <strong>yüksek doğrulukla başlayın</strong>; yapıyı hızlıca taslaklamak için tel çerçeveyi kullanın.</li>\n<li><strong>Tasarımlarınız proje klasörüyle birlikte kalır</strong> — Open Design'ı doğru dizin üzerinde çalıştırarak işinizi organize edin.</li>\n<li><strong>Kendi medya anahtarlarınızı getirin</strong>, yalnızca gerçekten kullandığınız sağlayıcılar için; hepsine ihtiyacınız yok.</li>\n<li><strong>Başlamak için bir tasarım sistemine ihtiyacınız yok.</strong> Yerleşik birinden başlayın, bir Claude Design ZIP'i içe aktarın ya da Open Design'ın varsayılanları çıkarsamasına izin verin.</li>\n</ul>\n\n<h2>SSS</h2>\n<p><strong>Open Design ücretsiz mi?</strong><br>Evet — Apache-2.0 lisansı altında açık kaynaklıdır. Yerel olarak ücretsiz çalıştırabilirsiniz; yalnızca bağladığınız agent ve medya sağlayıcılarının model/API kullanımı için ödeme yaparsınız.</p>\n<p><strong>Hangi kodlama agent'larını destekliyor?</strong><br>Claude Code, Codex, Cursor, Gemini, GitHub Copilot ve OpenCode dahil 21+ agent. Open Design makinenizde zaten kurulu olan CLI'leri algılar.</p>\n<p><strong>Tasarım yapabilmek için önce bir tasarım sistemi oluşturmam gerekiyor mu?</strong><br>Hayır. Claude Design'ın aksine, Open Design size çalışan varsayılanlar ve bir başlangıç noktaları galerisi verir. İstediğinizde kendi tasarım sisteminizi getirebilirsiniz.</p>\n<p><strong>Claude Design'dan farkı ne?</strong><br>Aynı tanıdık his, ama açık kaynaklı, önce-yerel ve agent takılabilir — ayrıca sunum desteleri, dergi düzenleri, görsel üretimi ve video gibi ek yetenekler.</p>\n\n<hr>\n<p><em>Bu yazılı rehber, CodingMenace'in ilk-izlenim anlatımına dayanmaktadır. Yukarıdaki tam videoyu izleyin ve daha fazla uygulamalı yapay zeka aracı videosu için <a href=\"https://www.youtube.com/watch?v=QOqWZzecjuY\">CodingMenace'e abone olun</a>.</em></p>",
    },
  },
};

export function getLocalizedTutorial(
  slug: string,
  locale: string,
): LocalizedTutorialContent | undefined {
  return tutorialsLongformI18n[slug]?.[locale];
}
